     1→//! Formula parser implementation for R-style formulas.
     2→
     3→use nom::{
     4→    IResult,
     5→    branch::alt,
     6→    bytes::complete::take_while1,
     7→    character::complete::{char, multispace0},
     8→    combinator::{map, opt, recognize},
     9→    multi::{many0, separated_list0},
    10→    sequence::{delimited, preceded, separated_pair, tuple},
    11→};
    12→use crate::types::ValidationError;
    13→use super::term::{Term, HrfSpec, TermParam};
    14→
    15→/// Formula expression AST.
    16→#[derive(Debug, Clone, PartialEq)]
    17→pub enum FormulaExpr {
    18→    /// Variable reference
    19→    Variable(String),
    20→    /// Function call (e.g., hrf(condition))
    21→    FunctionCall {
    22→        name: String,
    23→        args: Vec<FormulaExpr>,
    24→        kwargs: Vec<(String, FormulaExpr)>,
    25→    },
    26→    /// Addition of terms
    27→    Addition(Box<FormulaExpr>, Box<FormulaExpr>),
    28→    /// Interaction between terms
    29→    Interaction(Box<FormulaExpr>, Box<FormulaExpr>),
    30→    /// String literal
    31→    StringLiteral(String),
    32→    /// Numeric literal
    33→    Number(f64),
    34→    /// Boolean literal
    35→    Boolean(bool),
    36→}
    37→
    38→/// Parsed formula representation.
    39→#[derive(Debug, Clone)]
    40→pub struct ParsedFormula {
    41→    /// Left-hand side (optional)
    42→    pub lhs: Option<String>,
    43→    /// Right-hand side expression
    44→    pub rhs: FormulaExpr,
    45→}
    46→
    47→/// Formula parser.
    48→pub struct FormulaParser;
    49→
    50→impl FormulaParser {
    51→    /// Create a new parser.
    52→    pub fn new() -> Self {
    53→        Self
    54→    }
    55→    
    56→    /// Parse a complete formula string.
    57→    pub fn parse(&self, input: &str) -> Result<ParsedFormula, ValidationError> {
    58→        let input = input.trim();
    59→        match parse_formula_internal(input) {
    60→            Ok((remaining, formula)) => {
    61→                let remaining = remaining.trim();
    62→                if !remaining.is_empty() {
    63→                    return Err(ValidationError::InvalidParameter(
    64→                        format!("Unexpected input after formula: '{}'", remaining)
    65→                    ));
    66→                }
    67→                Ok(formula)
    68→            }
    69→            Err(e) => Err(ValidationError::InvalidParameter(
    70→                format!("Failed to parse formula: {:?}", e)
    71→            )),
    72→        }
    73→    }
    74→    
    75→    /// Convert parsed formula to terms.
    76→    pub fn to_terms(&self, formula: &ParsedFormula) -> Result<Vec<Term>, ValidationError> {
    77→        expr_to_terms(&formula.rhs)
    78→    }
    79→}
    80→
    81→// Parser combinators
    82→
    83→/// Parse identifier (variable or function name).
    84→fn identifier(input: &str) -> IResult<&str, &str> {
    85→    recognize(
    86→        tuple((
    87→            take_while1(|c: char| c.is_alphabetic() || c == '_'),
    88→            opt(take_while1(|c: char| c.is_alphanumeric() || c == '_' || c == '.')),
    89→        ))
    90→    )(input)
    91→}
    92→
    93→/// Parse a number.
    94→fn number(input: &str) -> IResult<&str, f64> {
    95→    map(
    96→        recognize(
    97→            tuple((
    98→                opt(char('-')),
    99→                take_while1(|c: char| c.is_numeric()),
   100→                opt(tuple((
   101→                    char('.'),
   102→                    take_while1(|c: char| c.is_numeric()),
   103→                ))),
   104→            ))
   105→        ),
   106→        |s: &str| s.parse::<f64>().unwrap(),
   107→    )(input)
   108→}
   109→
   110→/// Parse a string literal.
   111→fn string_literal(input: &str) -> IResult<&str, String> {
   112→    alt((
   113→        delimited(
   114→            char('"'),
   115→            map(take_while1(|c| c != '"'), String::from),
   116→            char('"'),
   117→        ),
   118→        delimited(
   119→            char('\''),
   120→            map(take_while1(|c| c != '\''), String::from),
   121→            char('\''),
   122→        ),
   123→    ))(input)
   124→}
   125→
   126→/// Parse a boolean literal.
   127→fn boolean(input: &str) -> IResult<&str, bool> {
   128→    alt((
   129→        map(nom::bytes::complete::tag("TRUE"), |_| true),
   130→        map(nom::bytes::complete::tag("True"), |_| true),
   131→        map(nom::bytes::complete::tag("true"), |_| true),
   132→        map(nom::bytes::complete::tag("FALSE"), |_| false),
   133→        map(nom::bytes::complete::tag("False"), |_| false),
   134→        map(nom::bytes::complete::tag("false"), |_| false),
   135→    ))(input)
   136→}
   137→
   138→/// Parse keyword argument (name=value).
   139→fn kwarg(input: &str) -> IResult<&str, (String, FormulaExpr)> {
   140→    map(
   141→        separated_pair(
   142→            identifier,
   143→            delimited(multispace0, char('='), multispace0),
   144→            alt((
   145→                map(number, FormulaExpr::Number),
   146→                map(boolean, FormulaExpr::Boolean),
   147→                map(string_literal, FormulaExpr::StringLiteral),
   148→                map(identifier, |s| FormulaExpr::Variable(s.to_string())),
   149→            )),
   150→        ),
   151→        |(name, value)| (name.to_string(), value),
   152→    )(input)
   153→}
   154→
   155→/// Parse function arguments (positional and keyword).
   156→fn function_args(input: &str) -> IResult<&str, (Vec<FormulaExpr>, Vec<(String, FormulaExpr)>)> {
   157→    let (input, args_and_kwargs) = separated_list0(
   158→        delimited(multispace0, char(','), multispace0),
   159→        alt((
   160→            // Try to parse as kwarg first
   161→            map(kwarg, |kw| (None, Some(kw))),
   162→            // Otherwise parse as positional arg
   163→            map(expression, |expr| (Some(expr), None)),
   164→        )),
   165→    )(input)?;
   166→    
   167→    // Separate positional and keyword arguments
   168→    let mut args = Vec::new();
   169→    let mut kwargs = Vec::new();
   170→    let mut seen_kwarg = false;
   171→    
   172→    for (arg, kwarg) in args_and_kwargs {
   173→        if let Some(kw) = kwarg {
   174→            seen_kwarg = true;
   175→            kwargs.push(kw);
   176→        } else if let Some(a) = arg {
   177→            if seen_kwarg {
   178→                // Positional arg after keyword arg is an error
   179→                return Err(nom::Err::Error(nom::error::Error::new(
   180→                    input,
   181→                    nom::error::ErrorKind::Tag,
   182→                )));
   183→            }
   184→            args.push(a);
   185→        }
   186→    }
   187→    
   188→    Ok((input, (args, kwargs)))
   189→}
   190→
   191→/// Parse a primary expression (variable, literal, or function call).
   192→fn primary_expr(input: &str) -> IResult<&str, FormulaExpr> {
   193→    delimited(
   194→        multispace0,
   195→        alt((
   196→            // Parenthesized expression
   197→            delimited(
   198→                char('('),
   199→                expression,
   200→                char(')'),
   201→            ),
   202→            // Number literal
   203→            map(number, FormulaExpr::Number),
   204→            // Boolean literal
   205→            map(boolean, FormulaExpr::Boolean),
   206→            // String literal
   207→            map(string_literal, FormulaExpr::StringLiteral),
   208→            // Function call or variable
   209→            map(
   210→                tuple((
   211→                    identifier,
   212→                    opt(delimited(
   213→                        char('('),
   214→                        function_args,
   215→                        char(')'),
   216→                    )),
   217→                )),
   218→                |(name, args_kwargs)| {
   219→                    if let Some((args, kwargs)) = args_kwargs {
   220→                        FormulaExpr::FunctionCall {
   221→                            name: name.to_string(),
   222→                            args,
   223→                            kwargs,
   224→                        }
   225→                    } else {
   226→                        FormulaExpr::Variable(name.to_string())
   227→                    }
   228→                }
   229→            ),
   230→        )),
   231→        multispace0,
   232→    )(input)
   233→}
   234→
   235→/// Parse interaction term (using : operator).
   236→fn interaction_expr(input: &str) -> IResult<&str, FormulaExpr> {
   237→    let (input, first) = primary_expr(input)?;
   238→    
   239→    // Parse additional interaction terms if any
   240→    let (input, rest) = many0(
   241→        preceded(
   242→            delimited(multispace0, char(':'), multispace0),
   243→            primary_expr,
   244→        )
   245→    )(input)?;
   246→    
   247→    // Fold all terms into a left-associative tree
   248→    Ok((input, rest.into_iter().fold(first, |acc, expr| {
   249→        FormulaExpr::Interaction(Box::new(acc), Box::new(expr))
   250→    })))
   251→}
   252→
   253→/// Parse addition expression.
   254→fn addition_expr(input: &str) -> IResult<&str, FormulaExpr> {
   255→    let (input, first) = interaction_expr(input)?;
   256→    
   257→    // Parse additional terms if any
   258→    let (input, rest) = many0(
   259→        preceded(
   260→            delimited(multispace0, char('+'), multispace0),
   261→            interaction_expr,
   262→        )
   263→    )(input)?;
   264→    
   265→    // Fold all terms into a left-associative tree
   266→    Ok((input, rest.into_iter().fold(first, |acc, expr| {
   267→        FormulaExpr::Addition(Box::new(acc), Box::new(expr))
   268→    })))
   269→}
   270→
   271→/// Parse a complete expression.
   272→fn expression(input: &str) -> IResult<&str, FormulaExpr> {
   273→    addition_expr(input)
   274→}
   275→
   276→/// Parse a complete formula (with optional LHS).
   277→fn parse_formula_internal(input: &str) -> IResult<&str, ParsedFormula> {
   278→    delimited(
   279→        multispace0,
   280→        alt((
   281→            // Formula with LHS and RHS
   282→            map(
   283→                separated_pair(
   284→                    identifier,
   285→                    delimited(multispace0, char('~'), multispace0),
   286→                    expression,
   287→                ),
   288→                |(lhs, rhs)| ParsedFormula {
   289→                    lhs: Some(lhs.to_string()),
   290→                    rhs,
   291→                }
   292→            ),
   293→            // Just RHS (no ~)
   294→            map(
   295→                expression,
   296→                |rhs| ParsedFormula {
   297→                    lhs: None,
   298→                    rhs,
   299→                }
   300→            ),
   301→        )),
   302→        multispace0,
   303→    )(input)
   304→}
   305→
   306→/// Convert expression to terms.
   307→fn expr_to_terms(expr: &FormulaExpr) -> Result<Vec<Term>, ValidationError> {
   308→    match expr {
   309→        FormulaExpr::Addition(left, right) => {
   310→            let mut terms = expr_to_terms(left)?;
   311→            terms.extend(expr_to_terms(right)?);
   312→            Ok(terms)
   313→        }
   314→        FormulaExpr::Variable(name) => {
   315→            Ok(vec![Term::new(name)])
   316→        }
   317→        FormulaExpr::Interaction(left, right) => {
   318→            let left_vars = extract_variables(left)?;
   319→            let right_vars = extract_variables(right)?;
   320→            let mut all_vars = left_vars;
   321→            all_vars.extend(right_vars);
   322→            Ok(vec![Term::interaction(all_vars)?])
   323→        }
   324→        FormulaExpr::FunctionCall { name, args, kwargs } => {
   325→            match name.as_str() {
   326→                "hrf" => {
   327→                    if args.is_empty() {
   328→                        return Err(ValidationError::InvalidParameter(
   329→                            "hrf() requires at least one argument".to_string()
   330→                        ));
   331→                    }
   332→                    
   333→                    // Check if the argument is a trialwise function call
   334→                    let mut term = if let FormulaExpr::FunctionCall { name: fname, .. } = &args[0] {
   335→                        if fname == "trialwise" {
   336→                            // Process the trialwise function and get the term
   337→                            let inner_terms = expr_to_terms(&args[0])?;
   338→                            if inner_terms.len() == 1 {
   339→                                inner_terms.into_iter().next().unwrap()
   340→                            } else {
   341→                                return Err(ValidationError::InvalidParameter(
   342→                                    "trialwise() should return exactly one term".to_string()
   343→                                ));
   344→                            }
   345→                        } else {
   346→                            // Regular function call - extract variables
   347→                            let event_vars = extract_variables(&args[0])?;
   348→                            if event_vars.len() == 1 {
   349→                                Term::new(&event_vars[0])
   350→                            } else {
   351→                                Term::interaction(event_vars)?
   352→                            }
   353→                        }
   354→                    } else {
   355→                        // Regular variable or interaction
   356→                        let event_vars = extract_variables(&args[0])?;
   357→                        if event_vars.len() == 1 {
   358→                            Term::new(&event_vars[0])
   359→                        } else {
   360→                            Term::interaction(event_vars)?
   361→                        }
   362→                    };
   363→                    
   364→                    // Check for HRF type in second positional argument
   365→                    if args.len() > 1 {
   366→                        if let FormulaExpr::StringLiteral(hrf_name) = &args[1] {
   367→                            term = term.with_hrf(hrf_name.as_str());
   368→                        }
   369→                    } else {
   370→                        // Default to canonical HRF
   371→                        term = term.with_hrf("canonical");
   372→                    }
   373→                    
   374→                    // Process keyword arguments
   375→                    for (key, value) in kwargs {
   376→                        match key.as_str() {
   377→                            "hrf" | "basis" => {
   378→                                if let FormulaExpr::StringLiteral(s) = value {
   379→                                    term = term.with_hrf(s.as_str());
   380→                                }
   381→                            }
   382→                            _ => {
   383→                                // Store other kwargs as parameters
   384→                                match value {
   385→                                    FormulaExpr::StringLiteral(s) => {
   386→                                        term = term.set_param(key, s.as_str());
   387→                                    }
   388→                                    FormulaExpr::Number(n) => {
   389→                                        term = term.set_param(key, *n);
   390→                                    }
   391→                                    _ => {}
   392→                                }
   393→                            }
   394→                        }
   395→                    }
   396→                    
   397→                    Ok(vec![term])
   398→                }
   399→                "trialwise" => {
   400→                    // Trialwise single-trial regressors
   401→                    use crate::trialwise::TrialwiseConfig;
   402→                    
   403→                    let mut config = TrialwiseConfig::default();
   404→                    
   405→                    // Process keyword arguments
   406→                    for (key, value) in kwargs {
   407→                        match key.as_str() {
   408→                            "basis" | "hrf" => {
   409→                                if let FormulaExpr::StringLiteral(s) = value {
   410→                                    config.basis = s.clone();
   411→                                }
   412→                            }
   413→                            "lag" => {
   414→                                if let FormulaExpr::Number(n) = value {
   415→                                    config.lag = *n;
   416→                                }
   417→                            }
   418→                            "nbasis" => {
   419→                                if let FormulaExpr::Number(n) = value {
   420→                                    config.nbasis = *n as usize;
   421→                                }
   422→                            }
   423→                            "add_sum" => {
   424→                                if let FormulaExpr::Boolean(b) = value {
   425→                                    config.add_sum = *b;
   426→                                }
   427→                            }
   428→                            "label" => {
   429→                                if let FormulaExpr::StringLiteral(s) = value {
   430→                                    config.label = s.clone();
   431→                                }
   432→                            }
   433→                            _ => {}
   434→                        }
   435→                    }
   436→                    
   437→                    let term = crate::trialwise::trialwise_with_config(config);
   438→                    Ok(vec![term])
   439→                }
   440→                "poly" => {
   441→                    // Polynomial basis function
   442→                    if args.is_empty() {
   443→                        return Err(ValidationError::InvalidParameter(
   444→                            "poly() requires at least one argument".to_string()
   445→                        ));
   446→                    }
   447→                    
   448→                    let event_vars = extract_variables(&args[0])?;
   449→                    let mut term = if event_vars.len() == 1 {
   450→                        Term::new(&event_vars[0])
   451→                    } else {
   452→                        Term::interaction(event_vars)?
   453→                    };
   454→                    
   455→                    // Get degree from second argument or kwargs
   456→                    let degree = if args.len() > 1 {
   457→                        if let FormulaExpr::Number(n) = &args[1] {
   458→                            *n as i32
   459→                        } else {
   460→                            2
   461→                        }
   462→                    } else {
   463→                        // Check kwargs for degree
   464→                        kwargs.iter()
   465→                            .find(|(k, _)| k == "degree")
   466→                            .and_then(|(_, v)| {
   467→                                if let FormulaExpr::Number(n) = v {
   468→                                    Some(*n as i32)
   469→                                } else {
   470→                                    None
   471→                                }
   472→                            })
   473→                            .unwrap_or(2)
   474→                    };
   475→                    
   476→                    // TODO: Create polynomial basis and attach to term
   477→                    term = term.set_param("poly_degree", degree as f64);
   478→                    
   479→                    Ok(vec![term])
   480→                }
   481→                "bs" => {
   482→                    // B-spline basis function
   483→                    if args.is_empty() {
   484→                        return Err(ValidationError::InvalidParameter(
   485→                            "bs() requires at least one argument".to_string()
   486→                        ));
   487→                    }
   488→                    
   489→                    let event_vars = extract_variables(&args[0])?;
   490→                    let mut term = if event_vars.len() == 1 {
   491→                        Term::new(&event_vars[0])
   492→                    } else {
   493→                        Term::interaction(event_vars)?
   494→                    };
   495→                    
   496→                    // Get df (degrees of freedom) from second argument or kwargs
   497→                    let df = if args.len() > 1 {
   498→                        if let FormulaExpr::Number(n) = &args[1] {
   499→                            *n as i32
   500→                        } else {
   501→                            4  // Default df
   502→                        }
   503→                    } else {
   504→                        // Check kwargs for df
   505→                        kwargs.iter()
   506→                            .find(|(k, _)| k == "df")
   507→                            .and_then(|(_, v)| {
   508→                                if let FormulaExpr::Number(n) = v {
   509→                                    Some(*n as i32)
   510→                                } else {
   511→                                    None
   512→                                }
   513→                            })
   514→                            .unwrap_or(4)
   515→                    };
   516→                    
   517→                    term = term.set_param("bs_df", df as f64);
   518→                    
   519→                    Ok(vec![term])
   520→                }
   521→                "scale" => {
   522→                    // Scale/standardize a variable
   523→                    if args.is_empty() {
   524→                        return Err(ValidationError::InvalidParameter(
   525→                            "scale() requires at least one argument".to_string()
   526→                        ));
   527→                    }
   528→                    
   529→                    let event_vars = extract_variables(&args[0])?;
   530→                    let mut term = if event_vars.len() == 1 {
   531→                        Term::new(&event_vars[0])
   532→                    } else {
   533→                        Term::interaction(event_vars)?
   534→                    };
   535→                    
   536→                    // Get centering option from kwargs
   537→                    let center = kwargs.iter()
   538→                        .find(|(k, _)| k == "center")
   539→                        .and_then(|(_, v)| {
   540→                            match v {
   541→                                FormulaExpr::Boolean(b) => Some(*b),
   542→                                _ => None
   543→                            }
   544→                        })
   545→                        .unwrap_or(true);
   546→                    
   547→                    // Get scaling option from kwargs
   548→                    let scale_bool = kwargs.iter()
   549→                        .find(|(k, _)| k == "scale")
   550→                        .and_then(|(_, v)| {
   551→                            match v {
   552→                                FormulaExpr::Boolean(b) => Some(*b),
   553→                                _ => None
   554→                            }
   555→                        })
   556→                        .unwrap_or(true);
   557→                    
   558→                    term = term.set_param("scale_center", if center { 1.0 } else { 0.0 });
   559→                    term = term.set_param("scale_scale", if scale_bool { 1.0 } else { 0.0 });
   560→                    
   561→                    Ok(vec![term])
   562→                }
   563→                "trialwise" => {
   564→                    // Use the trialwise module's function
   565→                    use crate::trialwise::TrialwiseConfig;
   566→                    let mut config = TrialwiseConfig::default();
   567→                    
   568→                    // Process kwargs
   569→                    for (key, value) in kwargs {
   570→                        match (key.as_str(), value) {
   571→                            ("basis", FormulaExpr::StringLiteral(s)) => {
   572→                                config.basis = s.clone();
   573→                            }
   574→                            ("lag", FormulaExpr::Number(n)) => {
   575→                                config.lag = *n;
   576→                            }
   577→                            ("nbasis", FormulaExpr::Number(n)) => {
   578→                                config.nbasis = *n as usize;
   579→                            }
   580→                            ("add_sum", FormulaExpr::Boolean(b)) => {
   581→                                config.add_sum = *b;
   582→                            }
   583→                            ("label", FormulaExpr::StringLiteral(s)) => {
   584→                                config.label = s.clone();
   585→                            }
   586→                            _ => {}
   587→                        }
   588→                    }
   589→                    
   590→                    let term = crate::trialwise::trialwise_with_config(config);
   591→                    Ok(vec![term])
   592→                }
   593→                "covariate" => {
   594→                    // Covariate function - no HRF convolution
   595→                    use crate::covariate::CovariateConfig;
   596→                    let mut config = CovariateConfig::default();
   597→                    
   598→                    // Extract variable names from args
   599→                    let mut covariate_names = Vec::new();
   600→                    for arg in args {
   601→                        if let Ok(vars) = extract_variables(arg) {
   602→                            covariate_names.extend(vars);
   603→                        }
   604→                    }
   605→                    
   606→                    // If no arguments, we'll use all numeric columns from the data later
   607→                    // For now, use a special marker
   608→                    if covariate_names.is_empty() {
   609→                        covariate_names.push("_all_covariates_".to_string());
   610→                    }
   611→                    
   612→                    config.covariates = covariate_names;
   613→                    
   614→                    // Process kwargs
   615→                    for (key, value) in kwargs {
   616→                        match (key.as_str(), value) {
   617→                            ("prefix", FormulaExpr::StringLiteral(s)) => {
   618→                                config.prefix = Some(s.clone());
   619→                            }
   620→                            _ => {}
   621→                        }
   622→                    }
   623→                    
   624→                    let term = crate::covariate::covariate_with_config(config);
   625→                    Ok(vec![term])
   626→                }
   627→                _ => Err(ValidationError::InvalidParameter(
   628→                    format!("Unknown function: {}", name)
   629→                )),
   630→            }
   631→        }
   632→        _ => Err(ValidationError::InvalidParameter(
   633→            "Invalid expression type in formula".to_string()
   634→        )),
   635→    }
   636→}
   637→
   638→/// Extract variable names from an expression.
   639→fn extract_variables(expr: &FormulaExpr) -> Result<Vec<String>, ValidationError> {
   640→    match expr {
   641→        FormulaExpr::Variable(name) => Ok(vec![name.clone()]),
   642→        FormulaExpr::Interaction(left, right) => {
   643→            let mut vars = extract_variables(left)?;
   644→            vars.extend(extract_variables(right)?);
   645→            Ok(vars)
   646→        }
   647→        FormulaExpr::FunctionCall { name, args, .. } => {
   648→            // Special case for trialwise() which doesn't need arguments
   649→            if name == "trialwise" {
   650→                Ok(vec!["_trialwise_placeholder_".to_string()])
   651→            } else if args.is_empty() {
   652→                // For function calls like poly(rt, 2), extract the variable from the first argument
   653→                Err(ValidationError::InvalidParameter(
   654→                    format!("Function {} requires arguments", name)
   655→                ))
   656→            } else {
   657→                extract_variables(&args[0])
   658→            }
   659→        }
   660→        _ => Err(ValidationError::InvalidParameter(
   661→            "Expected variable or interaction in expression".to_string()
   662→        )),
   663→    }
   664→}
   665→
   666→/// Parse a formula string and convert to terms.
   667→pub fn parse_formula(input: &str) -> Result<Vec<Term>, ValidationError> {
   668→    let parser = FormulaParser::new();
   669→    let parsed = parser.parse(input)?;
   670→    parser.to_terms(&parsed)
   671→}
