     1→//! Core Term structure for formula specification.
     2→
     3→use std::collections::HashMap;
     4→use crate::types::{BasisFunction, ValidationError};
     5→
     6→/// Represents a term in an event model formula.
     7→///
     8→/// A term specifies how one or more events are transformed and combined
     9→/// to create columns in the design matrix.
    10→#[derive(Debug)]
    11→pub struct Term {
    12→    /// Event variable name(s). If multiple, creates an interaction.
    13→    pub events: Vec<String>,
    14→    /// HRF specification (name or parameters)
    15→    pub hrf: Option<HrfSpec>,
    16→    /// Basis function for continuous variables
    17→    pub basis: Option<Box<dyn BasisFunction>>,
    18→    /// Custom name for this term
    19→    pub name: Option<String>,
    20→    /// Additional parameters
    21→    pub params: HashMap<String, TermParam>,
    22→}
    23→
    24→impl Clone for Term {
    25→    fn clone(&self) -> Self {
    26→        Self {
    27→            events: self.events.clone(),
    28→            hrf: self.hrf.clone(),
    29→            basis: None, // Cannot clone trait objects, so we skip basis
    30→            name: self.name.clone(),
    31→            params: self.params.clone(),
    32→        }
    33→    }
    34→}
    35→
    36→/// HRF specification
    37→#[derive(Debug, Clone)]
    38→pub enum HrfSpec {
    39→    /// Named HRF (e.g., "spm_canonical", "gamma")
    40→    Named(String),
    41→    /// Custom HRF parameters
    42→    Custom(HashMap<String, f64>),
    43→}
    44→
    45→impl From<&str> for HrfSpec {
    46→    fn from(s: &str) -> Self {
    47→        HrfSpec::Named(s.to_string())
    48→    }
    49→}
    50→
    51→impl From<String> for HrfSpec {
    52→    fn from(s: String) -> Self {
    53→        HrfSpec::Named(s)
    54→    }
    55→}
    56→
    57→/// Parameter value for terms
    58→#[derive(Debug, Clone)]
    59→pub enum TermParam {
    60→    /// String value
    61→    String(String),
    62→    /// Numeric value
    63→    Number(f64),
    64→    /// Boolean value
    65→    Bool(bool),
    66→    /// List of strings
    67→    StringList(Vec<String>),
    68→    /// List of numbers
    69→    NumberList(Vec<f64>),
    70→}
    71→
    72→impl Term {
    73→    /// Create a new term with a single event.
    74→    pub fn new(event: impl Into<String>) -> Self {
    75→        Self {
    76→            events: vec![event.into()],
    77→            hrf: None,
    78→            basis: None,
    79→            name: None,
    80→            params: HashMap::new(),
    81→        }
    82→    }
    83→    
    84→    /// Create a new term with multiple events (interaction).
    85→    pub fn interaction(events: Vec<String>) -> Result<Self, ValidationError> {
    86→        if events.len() < 2 {
    87→            return Err(ValidationError::InvalidParameter(
    88→                "Interaction requires at least 2 events".to_string()
    89→            ));
    90→        }
    91→        
    92→        Ok(Self {
    93→            events,
    94→            hrf: None,
    95→            basis: None,
    96→            name: None,
    97→            params: HashMap::new(),
    98→        })
    99→    }
   100→    
   101→    /// Set HRF for this term.
   102→    pub fn with_hrf(mut self, hrf: impl Into<HrfSpec>) -> Self {
   103→        self.hrf = Some(hrf.into());
   104→        self
   105→    }
   106→    
   107→    /// Set basis function for this term.
   108→    pub fn with_basis(mut self, basis: Box<dyn BasisFunction>) -> Self {
   109→        self.basis = Some(basis);
   110→        self
   111→    }
   112→    
   113→    /// Set custom name for this term.
   114→    pub fn with_name(mut self, name: impl Into<String>) -> Self {
   115→        self.name = Some(name.into());
   116→        self
   117→    }
   118→    
   119→    /// Set a parameter.
   120→    pub fn set_param(mut self, key: impl Into<String>, value: impl Into<TermParam>) -> Self {
   121→        self.params.insert(key.into(), value.into());
   122→        self
   123→    }
   124→    
   125→    /// Get the effective name for this term.
   126→    pub fn effective_name(&self) -> String {
   127→        if let Some(ref name) = self.name {
   128→            name.clone()
   129→        } else if self.is_interaction() {
   130→            self.events.join(":")
   131→        } else {
   132→            self.events[0].clone()
   133→        }
   134→    }
   135→    
   136→    /// Check if this is an interaction term.
   137→    pub fn is_interaction(&self) -> bool {
   138→        self.events.len() > 1
   139→    }
   140→    
