//! Covariate support for fMRI models.
//!
//! Covariates are terms that are added directly to the design matrix without
//! HRF convolution. They are useful for including nuisance variables, motion
//! parameters, physiological measurements, or other regressors.

use ndarray::Array1;
use crate::types::{EventSpec, EventType, OnsetArray, DurationArray, Array, ValidationError};
use crate::formula::Term;

/// Event representation for covariate data.
///
/// This is a special event type that holds covariate data
/// for direct inclusion in the design matrix without HRF convolution.
#[derive(Debug, Clone)]
pub struct CovariateEvent {
    /// Covariate name
    pub name: String,
    /// Covariate values (must match number of timepoints)
    pub values: Array1<f64>,
    /// Time points corresponding to values (optional)
    pub sampling_points: Option<Array1<f64>>,
    /// Empty arrays for EventSpec trait
    empty_onsets: OnsetArray,
    empty_durations: DurationArray,
}

impl CovariateEvent {
    /// Create a new covariate event.
    ///
    /// # Arguments
    /// * `name` - Covariate name
    /// * `values` - Covariate values (must match number of timepoints)
    /// * `sampling_points` - Time points corresponding to values (optional)
    ///
    /// # Example
    /// ```
    /// use fmridesign::covariate::CovariateEvent;
    /// use ndarray::array;
    /// 
    /// // Motion parameter
    /// let motion_x = CovariateEvent::new(
    ///     "motion_x",
    ///     array![0.1, 0.2, -0.1, 0.0, 0.3],
    ///     None,
    /// ).unwrap();
    /// ```
    pub fn new(
        name: impl Into<String>,
        values: Array1<f64>,
        sampling_points: Option<Array1<f64>>,
    ) -> Result<Self, ValidationError> {
        let name = name.into();

        // Validate values are finite
        if !values.iter().all(|v| v.is_finite()) {
            return Err(ValidationError::NonFiniteValues);
        }

        // If sampling points provided, validate length matches
        if let Some(ref sp) = sampling_points {
            if sp.len() != values.len() {
                return Err(ValidationError::LengthMismatch {
                    expected: values.len(),
                    actual: sp.len(),
                });
            }
        }

        Ok(Self {
            name,
            values,
            sampling_points,
            empty_onsets: OnsetArray::zeros(0),
            empty_durations: DurationArray::zeros(0),
        })
    }

    /// Number of timepoints.
    pub fn n_timepoints(&self) -> usize {
        self.values.len()
    }

    /// Interpolate values to match requested sampling points if needed.
    fn interpolate_to_sampling_points(&self, sampling_points: &Array1<f64>) -> Result<Array1<f64>, ValidationError> {
        if let Some(ref sp) = self.sampling_points {
            if sp == sampling_points {
                // Exact match - no interpolation needed
                Ok(self.values.clone())
            } else {
                // Need to interpolate - for now just do nearest neighbor
                // TODO: Implement proper linear interpolation
                let mut result = Array1::zeros(sampling_points.len());

                for (i, &target_time) in sampling_points.iter().enumerate() {
                    // Find nearest time point
                    let nearest_idx = sp.iter()
                        .enumerate()
                        .min_by_key(|(_, &t)| ((t - target_time).abs() * 1000.0) as i64)
                        .map(|(idx, _)| idx)
                        .unwrap_or(0);

                    result[i] = self.values[nearest_idx];
                }

                Ok(result)
            }
        } else {
            // No explicit sampling points - assume values match requested points
            if self.values.len() != sampling_points.len() {
                Err(ValidationError::LengthMismatch {
                    expected: sampling_points.len(),
                    actual: self.values.len(),
                })
            } else {
                Ok(self.values.clone())
            }
        }
    }
}

impl EventSpec for CovariateEvent {
    fn name(&self) -> &str {
        &self.name
    }

    fn event_type(&self) -> EventType {
        EventType::Continuous  // Covariates are treated as continuous
    }

    fn onsets(&self) -> &OnsetArray {
        // Covariates don't have traditional onsets
        &self.empty_onsets
    }

    fn durations(&self) -> &DurationArray {
        // Covariates don't have traditional durations
        &self.empty_durations
    }

    fn design_matrix(&self, sampling_points: &Array1<f64>) -> Result<Array, ValidationError> {
        // Get interpolated values
        let values = self.interpolate_to_sampling_points(sampling_points)?;

        // Return as column vector
        Ok(values.insert_axis(ndarray::Axis(1)))
    }

    fn as_any(&self) -> &dyn std::any::Any {
        self
    }
}

/// Configuration for covariate terms.
#[derive(Debug, Clone)]
pub struct CovariateConfig {
    /// Covariate variable names
    pub covariates: Vec<String>,
    /// Optional prefix for column names
    pub prefix: Option<String>,
}

impl Default for CovariateConfig {
    fn default() -> Self {
        Self {
            covariates: Vec::new(),
            prefix: None,
        }
    }
}

/// Create a covariate term for non-convolved regressors.
///
/// Covariates are added directly to the design matrix without HRF convolution.
/// This is useful for nuisance regressors, motion parameters, physiological
/// signals, or other variables that should not be convolved.
///
/// # Examples
/// ```ignore
/// // Motion parameters
/// let motion_term = covariate(vec!["motion_x", "motion_y", "motion_z"])
///     .with_prefix("motion");
/// 
/// // In event model formula
/// let model = event_model(
///     "hrf(stimulus) + covariate(motion_x, motion_y)",
///     &data,
///     tr,
///     n_scans
/// )?;
/// ```
pub fn covariate(variables: Vec<String>) -> Term {
    covariate_with_config(CovariateConfig {
        covariates: variables,
        prefix: None,
    })
}

/// Create a covariate term with custom configuration.
pub fn covariate_with_config(config: CovariateConfig) -> Term {
    // Create a special term that will be expanded during model construction
    let mut term = Term::new("_covariate_placeholder_");

    // Store configuration as parameters
    term = term.set_param("_is_covariate", 1.0);

    // Store covariate names as a comma-separated string for now
    // (since we can't store string lists in TermParam directly)
    term = term.set_param("_covariate_names", config.covariates.join(","));

    // Generate name
    let name = if let Some(ref prefix) = &config.prefix {
        format!("{}_{}", prefix, config.covariates.join("_"))
    } else {
        config.covariates.join("_")
    };

    if let Some(prefix) = config.prefix {
        term = term.set_param("_covariate_prefix", prefix);
    }

    term.with_name(name)
}

/// Check if a term is a covariate term.
pub fn is_covariate_term(term: &Term) -> bool {
    term.get_param("_is_covariate")
        .map(|v| v > 0.5)
        .unwrap_or(false)
}

/// Get covariate configuration from a term.
pub fn get_covariate_config(term: &Term) -> Option<CovariateConfig> {
    if !is_covariate_term(term) {
        return None;
    }

    // Extract covariate names from the parameter
    let covariates = term.params.get("_covariate_names")
        .and_then(|p| {
            if let crate::formula::TermParam::String(s) = p {
                Some(s.split(',').map(|s| s.to_string()).collect())
            } else {
                None
            }
        })
        .unwrap_or_default();

    let prefix = term.params.get("_covariate_prefix")
        .and_then(|p| {
            if let crate::formula::TermParam::String(s) = p {
                Some(s.clone())
            } else {
                None
            }
        });

    Some(CovariateConfig {
        covariates,
        prefix,
    })
}

/// Create covariate events from data columns.
pub fn create_covariate_events(
    data: &crate::core::DataFrame,
    covariate_names: &[String],
    n_timepoints: usize,
    prefix: Option<&str>,
) -> Result<Vec<CovariateEvent>, ValidationError> {
    let mut events = Vec::new();

    for cov_name in covariate_names {
        // Get values from data
        let values = data.get_column(cov_name)
            .ok_or_else(|| ValidationError::InvalidParameter(
                format!("Covariate '{}' not found in data", cov_name)
            ))?;

        // Validate length
        if values.len() != n_timepoints {
            return Err(ValidationError::LengthMismatch {
                expected: n_timepoints,
                actual: values.len(),
            });
        }

        // Use the covariate name directly - prefix will be handled by column naming
        let event_name = cov_name.clone();

        // Create covariate event
        let event = CovariateEvent::new(
            event_name,
            Array1::from(values.clone()),
            None,  // No explicit sampling points
        )?;

        events.push(event);
    }

    Ok(events)
}

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::array;

    #[test]
    fn test_covariate_event() {
        let values = array![0.1, 0.2, -0.1, 0.0, 0.3];
        let event = CovariateEvent::new("motion_x", values.clone(), None).unwrap();

        assert_eq!(event.name(), "motion_x");
        assert_eq!(event.n_timepoints(), 5);
        assert_eq!(event.event_type(), EventType::Continuous);

        // Test design matrix generation
        let sampling_points = array![0.0, 1.0, 2.0, 3.0, 4.0];
        let dm = event.design_matrix(&sampling_points).unwrap();

        assert_eq!(dm.shape(), &[5, 1]);
        assert_eq!(dm.column(0), values.view());
    }

    #[test]
    fn test_covariate_validation() {
        // Non-finite values should fail
        let values = array![0.1, f64::NAN, 0.3];
        let result = CovariateEvent::new("bad", values, None);
        assert!(result.is_err());

        // Mismatched sampling points should fail
        let values = array![0.1, 0.2, 0.3];
        let sp = array![0.0, 1.0];  // Wrong length
        let result = CovariateEvent::new("bad", values, Some(sp));
        assert!(result.is_err());
    }

    #[test]
    fn test_covariate_term() {
        let term = covariate(vec!["motion_x".to_string(), "motion_y".to_string()]);

        assert!(is_covariate_term(&term));

        let config = get_covariate_config(&term).unwrap();
        assert_eq!(config.covariates, vec!["motion_x", "motion_y"]);
        assert_eq!(config.prefix, None);
    }

    #[test]
    fn test_covariate_with_prefix() {
        let mut config = CovariateConfig::default();
        config.covariates = vec!["x".to_string(), "y".to_string(), "z".to_string()];
        config.prefix = Some("motion".to_string());

        let term = covariate_with_config(config);

        assert!(is_covariate_term(&term));
        assert_eq!(term.name, Some("motion_x_y_z".to_string()));

        let retrieved_config = get_covariate_config(&term).unwrap();
        assert_eq!(retrieved_config.prefix, Some("motion".to_string()));
    }
}

//! Formula parser implementation for R-style formulas.

use nom::{
    IResult,
    branch::alt,
    bytes::complete::take_while1,
    character::complete::{char, multispace0},
    combinator::{map, opt, recognize},
    multi::{many0, separated_list0},
    sequence::{delimited, preceded, separated_pair, tuple},
};
use crate::types::ValidationError;
use super::term::{Term, HrfSpec, TermParam};

/// Formula expression AST.
#[derive(Debug, Clone, PartialEq)]
pub enum FormulaExpr {
    /// Variable reference
    Variable(String),
    /// Function call (e.g., hrf(condition))
    FunctionCall {
        name: String,
        args: Vec<FormulaExpr>,
        kwargs: Vec<(String, FormulaExpr)>,
    },
    /// Addition of terms
    Addition(Box<FormulaExpr>, Box<FormulaExpr>),
    /// Interaction between terms
    Interaction(Box<FormulaExpr>, Box<FormulaExpr>),
    /// String literal
    StringLiteral(String),
    /// Numeric literal
    Number(f64),
    /// Boolean literal
    Boolean(bool),
}

/// Parsed formula representation.
#[derive(Debug, Clone)]
pub struct ParsedFormula {
    /// Left-hand side (optional)
    pub lhs: Option<String>,
    /// Right-hand side expression
    pub rhs: FormulaExpr,
}

/// Formula parser.
pub struct FormulaParser;

impl FormulaParser {
    /// Create a new parser.
    pub fn new() -> Self {
        Self
    }

    /// Parse a complete formula string.
    pub fn parse(&self, input: &str) -> Result<ParsedFormula, ValidationError> {
        let input = input.trim();
        match parse_formula_internal(input) {
            Ok((remaining, formula)) => {
                let remaining = remaining.trim();
                if !remaining.is_empty() {
                    return Err(ValidationError::InvalidParameter(
                        format!("Unexpected input after formula: '{}'", remaining)
                    ));
                }
                Ok(formula)
            }
            Err(e) => Err(ValidationError::InvalidParameter(
                format!("Failed to parse formula: {:?}", e)
            )),
        }
    }

    /// Convert parsed formula to terms.
    pub fn to_terms(&self, formula: &ParsedFormula) -> Result<Vec<Term>, ValidationError> {
        expr_to_terms(&formula.rhs)
    }
}

// Parser combinators

/// Parse identifier (variable or function name).
fn identifier(input: &str) -> IResult<&str, &str> {
    recognize(
        tuple((
            take_while1(|c: char| c.is_alphabetic() || c == '_'),
            opt(take_while1(|c: char| c.is_alphanumeric() || c == '_' || c == '.')),
        ))
    )(input)
}

/// Parse a number.
fn number(input: &str) -> IResult<&str, f64> {
    map(
        recognize(
            tuple((
                opt(char('-')),
                take_while1(|c: char| c.is_numeric()),
                opt(tuple((
                    char('.'),
                    take_while1(|c: char| c.is_numeric()),
                ))),
            ))
        ),
        |s: &str| s.parse::<f64>().unwrap(),
    )(input)
}

/// Parse a string literal.
fn string_literal(input: &str) -> IResult<&str, String> {
    alt((
        delimited(
            char('"'),
            map(take_while1(|c| c != '"'), String::from),
            char('"'),
        ),
        delimited(
            char('\''),
            map(take_while1(|c| c != '\''), String::from),
            char('\''),
        ),
    ))(input)
}

/// Parse a boolean literal.
fn boolean(input: &str) -> IResult<&str, bool> {
    alt((
        map(nom::bytes::complete::tag("TRUE"), |_| true),
        map(nom::bytes::complete::tag("True"), |_| true),
        map(nom::bytes::complete::tag("true"), |_| true),
        map(nom::bytes::complete::tag("FALSE"), |_| false),
        map(nom::bytes::complete::tag("False"), |_| false),
        map(nom::bytes::complete::tag("false"), |_| false),
    ))(input)
}

/// Parse keyword argument (name=value).
fn kwarg(input: &str) -> IResult<&str, (String, FormulaExpr)> {
    map(
        separated_pair(
            identifier,
            delimited(multispace0, char('='), multispace0),
            alt((
                map(number, FormulaExpr::Number),
                map(boolean, FormulaExpr::Boolean),
                map(string_literal, FormulaExpr::StringLiteral),
                map(identifier, |s| FormulaExpr::Variable(s.to_string())),
            )),
        ),
        |(name, value)| (name.to_string(), value),
    )(input)
}

/// Parse function arguments (positional and keyword).
fn function_args(input: &str) -> IResult<&str, (Vec<FormulaExpr>, Vec<(String, FormulaExpr)>)> {
    let (input, args_and_kwargs) = separated_list0(
        delimited(multispace0, char(','), multispace0),
        alt((
            // Try to parse as kwarg first
            map(kwarg, |kw| (None, Some(kw))),
            // Otherwise parse as positional arg
            map(expression, |expr| (Some(expr), None)),
        )),
    )(input)?;

    // Separate positional and keyword arguments
    let mut args = Vec::new();
    let mut kwargs = Vec::new();
    let mut seen_kwarg = false;

    for (arg, kwarg) in args_and_kwargs {
        if let Some(kw) = kwarg {
            seen_kwarg = true;
            kwargs.push(kw);
        } else if let Some(a) = arg {
            if seen_kwarg {
                // Positional arg after keyword arg is an error
                return Err(nom::Err::Error(nom::error::Error::new(
                    input,
                    nom::error::ErrorKind::Tag,
                )));
            }
            args.push(a);
        }
    }

    Ok((input, (args, kwargs)))
}

/// Parse a primary expression (variable, literal, or function call).
fn primary_expr(input: &str) -> IResult<&str, FormulaExpr> {
    delimited(
        multispace0,
        alt((
            // Parenthesized expression
            delimited(
                char('('),
                expression,
                char(')'),
            ),
            // Number literal
            map(number, FormulaExpr::Number),
            // Boolean literal
            map(boolean, FormulaExpr::Boolean),
            // String literal
            map(string_literal, FormulaExpr::StringLiteral),
            // Function call or variable
            map(
                tuple((
                    identifier,
                    opt(delimited(
                        char('('),
                        function_args,
                        char(')'),
                    )),
                )),
                |(name, args_kwargs)| {
                    if let Some((args, kwargs)) = args_kwargs {
                        FormulaExpr::FunctionCall {
                            name: name.to_string(),
                            args,
                            kwargs,
                        }
                    } else {
                        FormulaExpr::Variable(name.to_string())
                    }
                }
            ),
        )),
        multispace0,
    )(input)
}

/// Parse interaction term (using : operator).
fn interaction_expr(input: &str) -> IResult<&str, FormulaExpr> {
    let (input, first) = primary_expr(input)?;

    // Parse additional interaction terms if any
    let (input, rest) = many0(
        preceded(
            delimited(multispace0, char(':'), multispace0),
            primary_expr,
        )
    )(input)?;

    // Fold all terms into a left-associative tree
    Ok((input, rest.into_iter().fold(first, |acc, expr| {
        FormulaExpr::Interaction(Box::new(acc), Box::new(expr))
    })))
}

/// Parse addition expression.
fn addition_expr(input: &str) -> IResult<&str, FormulaExpr> {
    let (input, first) = interaction_expr(input)?;

    // Parse additional terms if any
    let (input, rest) = many0(
        preceded(
            delimited(multispace0, char('+'), multispace0),
            interaction_expr,
        )
    )(input)?;

    // Fold all terms into a left-associative tree
    Ok((input, rest.into_iter().fold(first, |acc, expr| {
        FormulaExpr::Addition(Box::new(acc), Box::new(expr))
    })))
}

/// Parse a complete expression.
fn expression(input: &str) -> IResult<&str, FormulaExpr> {
    addition_expr(input)
}

/// Parse a complete formula (with optional LHS).
fn parse_formula_internal(input: &str) -> IResult<&str, ParsedFormula> {
    delimited(
        multispace0,
        alt((
            // Formula with LHS and RHS
            map(
                separated_pair(
                    identifier,
                    delimited(multispace0, char('~'), multispace0),
                    expression,
                ),
                |(lhs, rhs)| ParsedFormula {
                    lhs: Some(lhs.to_string()),
                    rhs,
                }
            ),
            // Just RHS (no ~)
            map(
                expression,
                |rhs| ParsedFormula {
                    lhs: None,
                    rhs,
                }
            ),
        )),
        multispace0,
    )(input)
}

/// Convert expression to terms.
fn expr_to_terms(expr: &FormulaExpr) -> Result<Vec<Term>, ValidationError> {
    match expr {
        FormulaExpr::Addition(left, right) => {
            let mut terms = expr_to_terms(left)?;
            terms.extend(expr_to_terms(right)?);
            Ok(terms)
        }
        FormulaExpr::Variable(name) => {
            Ok(vec![Term::new(name)])
        }
        FormulaExpr::Interaction(left, right) => {
            let left_vars = extract_variables(left)?;
            let right_vars = extract_variables(right)?;
            let mut all_vars = left_vars;
            all_vars.extend(right_vars);
            Ok(vec![Term::interaction(all_vars)?])
        }
        FormulaExpr::FunctionCall { name, args, kwargs } => {
            match name.as_str() {
                "hrf" => {
                    if args.is_empty() {
                        return Err(ValidationError::InvalidParameter(
                            "hrf() requires at least one argument".to_string()
                        ));
                    }

                    // Check if the argument is a trialwise function call
                    let mut term = if let FormulaExpr::FunctionCall { name: fname, .. } = &args[0] {
                        if fname == "trialwise" {
                            // Process the trialwise function and get the term
                            let inner_terms = expr_to_terms(&args[0])?;
                            if inner_terms.len() == 1 {
                                inner_terms.into_iter().next().unwrap()
                            } else {
                                return Err(ValidationError::InvalidParameter(
                                    "trialwise() should return exactly one term".to_string()
                                ));
                            }
                        } else {
                            // Regular function call - extract variables
                            let event_vars = extract_variables(&args[0])?;
                            if event_vars.len() == 1 {
                                Term::new(&event_vars[0])
                            } else {
                                Term::interaction(event_vars)?
                            }
                        }
                    } else {
                        // Regular variable or interaction
                        let event_vars = extract_variables(&args[0])?;
                        if event_vars.len() == 1 {
                            Term::new(&event_vars[0])
                        } else {
                            Term::interaction(event_vars)?
                        }
                    };

                    // Check for HRF type in second positional argument
                    if args.len() > 1 {
                        if let FormulaExpr::StringLiteral(hrf_name) = &args[1] {
                            term = term.with_hrf(hrf_name.as_str());
                        }
                    } else {
                        // Default to canonical HRF
                        term = term.with_hrf("canonical");
                    }

                    // Process keyword arguments
                    for (key, value) in kwargs {
                        match key.as_str() {
                            "hrf" | "basis" => {
                                if let FormulaExpr::StringLiteral(s) = value {
                                    term = term.with_hrf(s.as_str());
                                }
                            }
                            _ => {
                                // Store other kwargs as parameters
                                match value {
                                    FormulaExpr::StringLiteral(s) => {
                                        term = term.set_param(key, s.as_str());
                                    }
                                    FormulaExpr::Number(n) => {
                                        term = term.set_param(key, *n);
                                    }
                                    _ => {}
                                }
                            }
                        }
                    }

                    Ok(vec![term])
                }
                "trialwise" => {
                    // Trialwise single-trial regressors
                    use crate::trialwise::TrialwiseConfig;

                    let mut config = TrialwiseConfig::default();

                    // Process keyword arguments
                    for (key, value) in kwargs {
                        match key.as_str() {
                            "basis" | "hrf" => {
                                if let FormulaExpr::StringLiteral(s) = value {
                                    config.basis = s.clone();
                                }
                            }
                            "lag" => {
                                if let FormulaExpr::Number(n) = value {
                                    config.lag = *n;
                                }
                            }
                            "nbasis" => {
                                if let FormulaExpr::Number(n) = value {
                                    config.nbasis = *n as usize;
                                }
                            }
                            "add_sum" => {
                                if let FormulaExpr::Boolean(b) = value {
                                    config.add_sum = *b;
                                }
                            }
                            "label" => {
                                if let FormulaExpr::StringLiteral(s) = value {
                                    config.label = s.clone();
                                }
                            }
                            _ => {}
                        }
                    }

                    let term = crate::trialwise::trialwise_with_config(config);
                    Ok(vec![term])
                }
                "poly" => {
                    // Polynomial basis function
                    if args.is_empty() {
                        return Err(ValidationError::InvalidParameter(
                            "poly() requires at least one argument".to_string()
                        ));
                    }

                    let event_vars = extract_variables(&args[0])?;
                    let mut term = if event_vars.len() == 1 {
                        Term::new(&event_vars[0])
                    } else {
                        Term::interaction(event_vars)?
                    };

                    // Get degree from second argument or kwargs
                    let degree = if args.len() > 1 {
                        if let FormulaExpr::Number(n) = &args[1] {
                            *n as i32
                        } else {
                            2
                        }
                    } else {
                        // Check kwargs for degree
                        kwargs.iter()
                            .find(|(k, _)| k == "degree")
                            .and_then(|(_, v)| {
                                if let FormulaExpr::Number(n) = v {
                                    Some(*n as i32)
                                } else {
                                    None
                                }
                            })
                            .unwrap_or(2)
                    };

                    // TODO: Create polynomial basis and attach to term
                    term = term.set_param("poly_degree", degree as f64);

                    Ok(vec![term])
                }
                "bs" => {
                    // B-spline basis function
                    if args.is_empty() {
                        return Err(ValidationError::InvalidParameter(
                            "bs() requires at least one argument".to_string()
                        ));
                    }

                    let event_vars = extract_variables(&args[0])?;
                    let mut term = if event_vars.len() == 1 {
                        Term::new(&event_vars[0])
                    } else {
                        Term::interaction(event_vars)?
                    };

                    // Get df (degrees of freedom) from second argument or kwargs
                    let df = if args.len() > 1 {
                        if let FormulaExpr::Number(n) = &args[1] {
                            *n as i32
                        } else {
                            4  // Default df
                        }
                    } else {
                        // Check kwargs for df
                        kwargs.iter()
                            .find(|(k, _)| k == "df")
                            .and_then(|(_, v)| {
                                if let FormulaExpr::Number(n) = v {
                                    Some(*n as i32)
                                } else {
                                    None
                                }
                            })
                            .unwrap_or(4)
                    };

                    term = term.set_param("bs_df", df as f64);

                    Ok(vec![term])
                }
                "scale" => {
                    // Scale/standardize a variable
                    if args.is_empty() {
                        return Err(ValidationError::InvalidParameter(
                            "scale() requires at least one argument".to_string()
                        ));
                    }

                    let event_vars = extract_variables(&args[0])?;
                    let mut term = if event_vars.len() == 1 {
                        Term::new(&event_vars[0])
                    } else {
                        Term::interaction(event_vars)?
                    };

                    // Get centering option from kwargs
                    let center = kwargs.iter()
                        .find(|(k, _)| k == "center")
                        .and_then(|(_, v)| {
                            match v {
                                FormulaExpr::Boolean(b) => Some(*b),
                                _ => None
                            }
                        })
                        .unwrap_or(true);

                    // Get scaling option from kwargs
                    let scale_bool = kwargs.iter()
                        .find(|(k, _)| k == "scale")
                        .and_then(|(_, v)| {
                            match v {
                                FormulaExpr::Boolean(b) => Some(*b),
                                _ => None
                            }
                        })
                        .unwrap_or(true);

                    term = term.set_param("scale_center", if center { 1.0 } else { 0.0 });
                    term = term.set_param("scale_scale", if scale_bool { 1.0 } else { 0.0 });

                    Ok(vec![term])
                }
                "trialwise" => {
                    // Use the trialwise module's function
                    use crate::trialwise::TrialwiseConfig;
                    let mut config = TrialwiseConfig::default();

                    // Process kwargs
                    for (key, value) in kwargs {
                        match (key.as_str(), value) {
                            ("basis", FormulaExpr::StringLiteral(s)) => {
                                config.basis = s.clone();
                            }
                            ("lag", FormulaExpr::Number(n)) => {
                                config.lag = *n;
                            }
                            ("nbasis", FormulaExpr::Number(n)) => {
                                config.nbasis = *n as usize;
                            }
                            ("add_sum", FormulaExpr::Boolean(b)) => {
                                config.add_sum = *b;
                            }
                            ("label", FormulaExpr::StringLiteral(s)) => {
                                config.label = s.clone();
                            }
                            _ => {}
                        }
                    }

                    let term = crate::trialwise::trialwise_with_config(config);
                    Ok(vec![term])
                }
                "covariate" => {
                    // Covariate function - no HRF convolution
                    use crate::covariate::CovariateConfig;
                    let mut config = CovariateConfig::default();

                    // Extract variable names from args
                    let mut covariate_names = Vec::new();
                    for arg in args {
                        if let Ok(vars) = extract_variables(arg) {
                            covariate_names.extend(vars);
                        }
                    }

                    // If no arguments, we'll use all numeric columns from the data later
                    // For now, use a special marker
                    if covariate_names.is_empty() {
                        covariate_names.push("_all_covariates_".to_string());
                    }

                    config.covariates = covariate_names;

                    // Process kwargs
                    for (key, value) in kwargs {
                        match (key.as_str(), value) {
                            ("prefix", FormulaExpr::StringLiteral(s)) => {
                                config.prefix = Some(s.clone());
                            }
                            _ => {}
                        }
                    }

                    let term = crate::covariate::covariate_with_config(config);
                    Ok(vec![term])
                }
                _ => Err(ValidationError::InvalidParameter(
                    format!("Unknown function: {}", name)
                )),
            }
        }
        _ => Err(ValidationError::InvalidParameter(
            "Invalid expression type in formula".to_string()
        )),
    }
}

/// Extract variable names from an expression.
fn extract_variables(expr: &FormulaExpr) -> Result<Vec<String>, ValidationError> {
    match expr {
        FormulaExpr::Variable(name) => Ok(vec![name.clone()]),
        FormulaExpr::Interaction(left, right) => {
            let mut vars = extract_variables(left)?;
            vars.extend(extract_variables(right)?);
            Ok(vars)
        }
        FormulaExpr::FunctionCall { name, args, .. } => {
            // Special case for trialwise() which doesn't need arguments
            if name == "trialwise" {
                Ok(vec!["_trialwise_placeholder_".to_string()])
            } else if args.is_empty() {
                // For function calls like poly(rt, 2), extract the variable from the first argument
                Err(ValidationError::InvalidParameter(
                    format!("Function {} requires arguments", name)
                ))
            } else {
                extract_variables(&args[0])
            }
        }
        _ => Err(ValidationError::InvalidParameter(
            "Expected variable or interaction in expression".to_string()
        )),
    }
}

/// Parse a formula string and convert to terms.
pub fn parse_formula(input: &str) -> Result<Vec<Term>, ValidationError> {
    let parser = FormulaParser::new();
    let parsed = parser.parse(input)?;
    parser.to_terms(&parsed)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_parse_simple_variable() {
        let parser = FormulaParser::new();
        let result = parser.parse("condition").unwrap();
        assert!(result.lhs.is_none());
        assert_eq!(result.rhs, FormulaExpr::Variable("condition".to_string()));
    }

    #[test]
    fn test_parse_addition() {
        let parser = FormulaParser::new();
        let result = parser.parse("condition + rating").unwrap();
        assert!(result.lhs.is_none());

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 2);
        assert_eq!(terms[0].events, vec!["condition"]);
        assert_eq!(terms[1].events, vec!["rating"]);
    }

    #[test]
    fn test_parse_interaction() {
        let parser = FormulaParser::new();
        let result = parser.parse("condition:block").unwrap();

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 1);
        assert_eq!(terms[0].events, vec!["condition", "block"]);
        assert!(terms[0].is_interaction());
    }

    #[test]
    fn test_parse_hrf_function() {
        let parser = FormulaParser::new();
        let result = parser.parse("hrf(condition)").unwrap();

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 1);
        assert_eq!(terms[0].events, vec!["condition"]);
    }

    #[test]
    fn test_parse_formula_with_lhs() {
        let parser = FormulaParser::new();
        let result = parser.parse("onset ~ condition + rating").unwrap();
        assert_eq!(result.lhs, Some("onset".to_string()));

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 2);
    }

    #[test]
    fn test_parse_complex_formula() {
        let parser = FormulaParser::new();
        let result = parser.parse("onset ~ hrf(condition) + hrf(rating) + condition:block").unwrap();

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 3);
        assert_eq!(terms[2].events, vec!["condition", "block"]);
    }

    #[test]
    fn test_parse_hrf_with_kwargs() {
        let parser = FormulaParser::new();
        let result = parser.parse("hrf(condition, hrf=\"gamma\")").unwrap();

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 1);
        assert_eq!(terms[0].events, vec!["condition"]);
        match &terms[0].hrf {
            Some(HrfSpec::Named(name)) => assert_eq!(name, "gamma"),
            _ => panic!("Expected named HRF"),
        }
    }

    #[test]
    fn test_parse_multiple_kwargs() {
        let parser = FormulaParser::new();
        let result = parser.parse("hrf(condition, hrf=\"spm_canonical\", duration=2.0)").unwrap();

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 1);

        // Check HRF
        match &terms[0].hrf {
            Some(HrfSpec::Named(name)) => assert_eq!(name, "spm_canonical"),
            _ => panic!("Expected named HRF"),
        }

        // Check duration parameter
        match terms[0].params.get("duration") {
            Some(TermParam::Number(n)) => assert_eq!(*n, 2.0),
            _ => panic!("Expected duration parameter"),
        }
    }

    #[test]
    fn test_parse_poly_function() {
        let parser = FormulaParser::new();
        let result = parser.parse("poly(rating, 3)").unwrap();

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 1);
        assert_eq!(terms[0].events, vec!["rating"]);

        // Check polynomial degree parameter
        match terms[0].params.get("poly_degree") {
            Some(TermParam::Number(n)) => assert_eq!(*n, 3.0),
            _ => panic!("Expected poly_degree parameter"),
        }
    }

    #[test]
    fn test_parse_trialwise_function() {
        let parser = FormulaParser::new();
        let result = parser.parse("trialwise(basis=\"spmg1\", lag=0.5)").unwrap();

        let terms = parser.to_terms(&result).unwrap();
        assert_eq!(terms.len(), 1);
        assert_eq!(terms[0].events, vec!["trialwise"]);

        // Check parameters
        match terms[0].params.get("basis") {
            Some(TermParam::String(s)) => assert_eq!(s, "spmg1"),
            _ => panic!("Expected basis parameter"),
        }

        match terms[0].params.get("lag") {
            Some(TermParam::Number(n)) => assert_eq!(*n, 0.5),
            _ => panic!("Expected lag parameter"),
        }
    }
}

