//! Single-trial regressor functionality for fMRI design matrices.
//!
//! This module provides the trialwise() function which creates one regressor
//! per trial in the event model, optionally with a grand-mean column.

use crate::types::{OnsetArray, DurationArray, ValidationError};
use crate::events::EventFactor;
use crate::formula::Term;
use ndarray::{Array1, Array2};

/// Configuration for trialwise regressors
#[derive(Debug, Clone)]
pub struct TrialwiseConfig {
    /// The hemodynamic response function or name
    pub basis: String,
    /// Temporal offset in seconds
    pub lag: f64,
    /// Number of basis functions
    pub nbasis: usize,
    /// Whether to add a grand-mean column
    pub add_sum: bool,
    /// Term label/prefix for columns
    pub label: String,
}

impl Default for TrialwiseConfig {
    fn default() -> Self {
        Self {
            basis: "spmg1".to_string(),
            lag: 0.0,
            nbasis: 1,
            add_sum: false,
            label: "trial".to_string(),
        }
    }
}

/// Generate one regressor per trial (plus an optional grand-mean column).
///
/// This creates individual regressors for each trial/event in the data,
/// allowing for single-trial analysis. Each trial gets its own column
/// in the design matrix.
///
/// # Examples
///
/// ```ignore
/// // Basic single-trial model
/// let model = event_model("hrf(trialwise())", &data, tr, n_scans)?;
///
/// // Single-trial with grand mean
/// let model = event_model("hrf(trialwise(add_sum=true))", &data, tr, n_scans)?;
/// ```
pub fn trialwise() -> Term {
    trialwise_with_config(TrialwiseConfig::default())
}

/// Generate trialwise regressors with custom configuration
pub fn trialwise_with_config(config: TrialwiseConfig) -> Term {
    // Create a special term that will be expanded during model construction
    let mut term = Term::new("_trialwise_placeholder_")
        .with_hrf(config.basis.clone())
        .with_name(config.label.clone());

    // Add special parameters for trialwise processing
    term = term
        .set_param("_is_trialwise", 1.0)
        .set_param("_add_sum", if config.add_sum { 1.0 } else { 0.0 })
        .set_param("_lag", config.lag)
        .set_param("_nbasis", config.nbasis as f64);

    // Store the label as a string parameter (encoded as numeric for now)
    // In practice, we'll handle this differently
    term
}

/// Create an EventFactor with unique levels for each trial
pub fn create_trial_factor(
    n_trials: usize,
    onsets: Option<&OnsetArray>,
    durations: Option<&DurationArray>,
    label: &str,
) -> Result<EventFactor, ValidationError> {
    // Determine padding for nice formatting
    let pad = n_trials.to_string().len();

    // Create trial labels with zero-padding
    let trial_labels: Vec<String> = (0..n_trials)
        .map(|i| format!("{:0width$}", i + 1, width = pad))
        .collect();

    // Use provided onsets or create default
    let trial_onsets = if let Some(onsets) = onsets {
        onsets.clone()
    } else {
        Array1::range(0.0, n_trials as f64, 1.0)
    };

    // Use provided durations or default to 0
    let trial_durations = if let Some(durations) = durations {
        durations.clone()
    } else {
        Array1::zeros(n_trials)
    };

    // Create EventFactor with unique level for each trial
    let trial_values: Vec<&str> = trial_labels.iter().map(|s| s.as_str()).collect();
    let trial_onsets_vec: Vec<f64> = trial_onsets.to_vec();
    let trial_durations_vec: Vec<f64> = trial_durations.to_vec();

    EventFactor::new(
        label.to_string(),
        trial_onsets_vec,
        trial_values,
        trial_durations_vec,
    )
}

/// Check if a term is a trialwise term
pub fn is_trialwise_term(term: &Term) -> bool {
    term.get_param("_is_trialwise")
        .map(|v| v > 0.5)
        .unwrap_or(false)
}

/// Get trialwise configuration from a term
pub fn get_trialwise_config(term: &Term) -> Option<TrialwiseConfig> {
    if !is_trialwise_term(term) {
        return None;
    }

    Some(TrialwiseConfig {
        basis: term.hrf.as_ref()
            .and_then(|h| {
                if let crate::formula::HrfSpec::Named(name) = h {
                    Some(name.clone())
                } else {
                    None
                }
            })
            .unwrap_or_else(|| "spmg1".to_string()),
        lag: term.get_param("_lag").unwrap_or(0.0),
        nbasis: term.get_param("_nbasis").map(|v| v as usize).unwrap_or(1),
        add_sum: term.get_param("_add_sum").map(|v| v > 0.5).unwrap_or(false),
        label: term.name.clone().unwrap_or_else(|| "trial".to_string()),
    })
}

/// Process trialwise columns by optionally adding a grand mean
pub fn process_trialwise_columns(
    columns: Array2<f64>,
    add_sum: bool,
) -> (Array2<f64>, Vec<String>) {
    let n_trials = columns.ncols();
    let label = "trial"; // Will be passed in from config
    let pad = n_trials.to_string().len();

    // Generate column names
    let mut col_names: Vec<String> = (0..n_trials)
        .map(|i| format!("{}_{:0width$}", label, i + 1, width = pad))
        .collect();

    if add_sum {
        // Calculate grand mean across trials
        let mean_col = columns.mean_axis(ndarray::Axis(1))
            .unwrap()
            .insert_axis(ndarray::Axis(1));

        // Concatenate original columns with mean
        let extended = ndarray::concatenate(
            ndarray::Axis(1),
            &[columns.view(), mean_col.view()]
        ).unwrap();

        col_names.push(format!("{}_mean", label));

        (extended, col_names)
    } else {
        (columns, col_names)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use ndarray::array;

    #[test]
    fn test_create_trial_factor() {
        let onsets = array![0.0, 2.0, 4.0, 6.0];
        let durations = array![1.0, 1.0, 1.0, 1.0];

        let factor = create_trial_factor(
            4,
            Some(&onsets),
            Some(&durations),
            "trial"
        ).unwrap();

        assert_eq!(factor.name(), "trial");
        assert_eq!(factor.levels().len(), 4);
        assert_eq!(factor.levels()[0], "1");
        assert_eq!(factor.levels()[3], "4");
    }

    #[test]
    fn test_trial_padding() {
        // Test padding for different numbers of trials
        let factor = create_trial_factor(100, None, None, "trial").unwrap();
        assert_eq!(factor.levels()[0], "001");
        assert_eq!(factor.levels()[99], "100");
    }

    #[test]
    fn test_process_trialwise_columns() {
        let cols = Array2::from_shape_fn((10, 3), |(i, j)| (i + j) as f64);

        // Without grand mean
        let (result, names) = process_trialwise_columns(cols.clone(), false);
        assert_eq!(result.shape(), &[10, 3]);
        assert_eq!(names.len(), 3);
        assert_eq!(names[0], "trial_1");

        // With grand mean
        let (result, names) = process_trialwise_columns(cols, true);
        assert_eq!(result.shape(), &[10, 4]);
        assert_eq!(names.len(), 4);
        assert_eq!(names[3], "trial_mean");
    }
}

//! Design matrix visualization functions.

use crate::core::EventModel;
use crate::types::ValidationError;
use plotters::prelude::*;
use std::path::Path;

// Helper macro for error conversion
macro_rules! plot_err {
    ($expr:expr) => {
        $expr.map_err(|e| ValidationError::ComputationError(e.to_string()))
    };
}

/// Configuration for design matrix visualization.
#[derive(Debug, Clone)]
pub struct DesignMapConfig {
    /// Figure size as (width, height) in pixels
    pub figsize: (u32, u32),
    /// Whether to draw separators between blocks/runs
    pub block_separators: bool,
    /// Whether to rotate x-axis labels
    pub rotate_x_text: bool,
    /// Color map to use
    pub colormap: ColorMap,
    /// Value limits for color scale (min, max)
    pub value_limits: Option<(f64, f64)>,
    /// Midpoint for diverging color scale
    pub midpoint: Option<f64>,
}

impl Default for DesignMapConfig {
    fn default() -> Self {
        Self {
            figsize: (800, 600),
            block_separators: true,
            rotate_x_text: true,
            colormap: ColorMap::Viridis,
            value_limits: None,
            midpoint: None,
        }
    }
}

/// Color map options for visualization.
#[derive(Debug, Clone, Copy)]
pub enum ColorMap {
    /// Blue to red diverging colormap
    BlueRed,
    /// Viridis sequential colormap
    Viridis,
    /// Grayscale
    Gray,
    /// Red to blue diverging (reversed)
    RedBlue,
}

impl ColorMap {
    /// Map a normalized value [0, 1] to RGB color.
    fn map(&self, value: f64) -> RGBColor {
        let v = value.clamp(0.0, 1.0);

        match self {
            ColorMap::BlueRed => {
                if v < 0.5 {
                    // Blue to white
                    let intensity = v * 2.0;
                    RGBColor(
                        (intensity * 255.0) as u8,
                        (intensity * 255.0) as u8,
                        255,
                    )
                } else {
                    // White to red
                    let intensity = (1.0 - v) * 2.0;
                    RGBColor(
                        255,
                        (intensity * 255.0) as u8,
                        (intensity * 255.0) as u8,
                    )
                }
            }
            ColorMap::RedBlue => {
                if v < 0.5 {
                    // Red to white
                    let intensity = v * 2.0;
                    RGBColor(
                        255,
                        (intensity * 255.0) as u8,
                        (intensity * 255.0) as u8,
                    )
                } else {
                    // White to blue
                    let intensity = (1.0 - v) * 2.0;
                    RGBColor(
                        (intensity * 255.0) as u8,
                        (intensity * 255.0) as u8,
                        255,
                    )
                }
            }
            ColorMap::Viridis => {
                // Simplified viridis colormap
                let r = (68.0 + v * (1.0 - 68.0/255.0) * 255.0) as u8;
                let g = ((1.0 + v * (231.0/255.0 - 1.0/255.0)) * 255.0) as u8;
                let b = ((84.0 + v * (55.0/255.0 - 84.0/255.0)) * 255.0) as u8;
                RGBColor(r, g, b)
            }
            ColorMap::Gray => {
                let gray = (v * 255.0) as u8;
                RGBColor(gray, gray, gray)
            }
        }
    }
}

/// Visualize design matrix as a heatmap.
///
/// Creates a heatmap visualization of the design matrix showing the
/// intensity of each regressor at each time point.
///
/// # Arguments
/// * `model` - Event model containing the design matrix to visualize
/// * `output_path` - Path to save the output image
/// * `config` - Visualization configuration
///
/// # Example
/// ```ignore
/// use fmridesign::visualization::{design_map, DesignMapConfig};
///
/// // Basic usage
/// design_map(&model, "design_matrix.png", &DesignMapConfig::default())?;
///
/// // Custom configuration
/// let config = DesignMapConfig {
///     figsize: (1200, 800),
///     colormap: ColorMap::BlueRed,
///     midpoint: Some(0.0),
///     ..Default::default()
/// };
/// design_map(&model, "design_matrix_custom.png", &config)?;
/// ```
pub fn design_map(
    model: &EventModel,
    output_path: impl AsRef<Path>,
    config: &DesignMapConfig,
) -> Result<(), ValidationError> {
    // Get design matrix
    let dm = model.get_design_matrix()
        .ok_or_else(|| ValidationError::InvalidParameter(
            "Design matrix not yet generated. Call generate_design_matrix() first.".to_string()
        ))
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw series: {}", e)))?;

    let matrix = &dm.data;
    let (n_scans, n_regressors) = (matrix.nrows(), matrix.ncols());

    // Create drawing backend
    let root = BitMapBackend::new(output_path.as_ref(), config.figsize)
        .into_drawing_area();

    plot_err!(root.fill(&WHITE))?;

    // Calculate layout
    let margin = 50;
    let colorbar_width = 60;
    let plot_area = root.margin(margin, margin, margin, margin);

    // Split into main plot and colorbar
    let plot_dim = plot_area.get_pixel_range();
    let plot_width = (plot_dim.0.end - plot_dim.0.start) as i32;
    let (main_area, colorbar_area) = plot_area.split_horizontally(plot_width - colorbar_width);

    // Get value range
    let (vmin, vmax) = if let Some(limits) = config.value_limits {
        limits
    } else {
        let min = matrix.iter().cloned().fold(f64::INFINITY, f64::min);
        let max = matrix.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
        (min, max)
    };

    // Adjust for midpoint if specified
    let (norm_vmin, norm_vmax) = if let Some(midpoint) = config.midpoint {
        let range = (vmax - midpoint).abs().max((vmin - midpoint).abs());
        (midpoint - range, midpoint + range)
    } else {
        (vmin, vmax)
    };

    // Draw heatmap
    let main_dim = main_area.get_pixel_range();
    let cell_width = (main_dim.0.end - main_dim.0.start) as f64 / n_regressors as f64;
    let cell_height = (main_dim.1.end - main_dim.1.start) as f64 / n_scans as f64;

    for i in 0..n_scans {
        for j in 0..n_regressors {
            let value = matrix[[i, j]];
            let normalized = if norm_vmax > norm_vmin {
                (value - norm_vmin) / (norm_vmax - norm_vmin)
            } else {
                0.5
            };

            let color = config.colormap.map(normalized);

            let x0 = (j as f64 * cell_width) as i32;
            let x1 = ((j + 1) as f64 * cell_width) as i32;
            let y0 = (i as f64 * cell_height) as i32;
            let y1 = ((i + 1) as f64 * cell_height) as i32;

            plot_err!(main_area.draw(&Rectangle::new(
                [(x0, y0), (x1, y1)],
                color.filled(),
            )))?;
        }
    }

    // Draw axes and labels
    let mut chart = ChartBuilder::on(&main_area)
        .caption(
            &format!("Design Matrix: {}", model.name()),
            ("sans-serif", 20).into_font()
        )
        .x_label_area_size(40)
        .y_label_area_size(40)
        .build_cartesian_2d(0f64..n_regressors as f64, 0f64..n_scans as f64)
        .map_err(|e| ValidationError::ComputationError(e.to_string()))?;

    // Configure mesh
    chart.configure_mesh()
        .x_desc("Regressors")
        .y_desc("Scan Number")
        .x_labels(n_regressors.min(20))
        .y_labels(10)
        .x_label_formatter(&|x| {
            let idx = *x as usize;
            if idx < dm.column_names.len() {
                // Truncate long names
                let name = &dm.column_names[idx];
                if name.len() > 10 {
                    format!("{}...", &name[..10])
                } else {
                    name.clone()
                }
            } else {
                String::new()
            }
        })
        .draw()
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw: {}", e)))?;

    // Draw colorbar
    draw_colorbar(&colorbar_area, config.colormap, norm_vmin, norm_vmax)
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw colorbar: {}", e)))?;

    root.present()
        .map_err(|e| ValidationError::ComputationError(format!("Failed to present chart: {}", e)))?;

    Ok(())
}

/// Draw a colorbar for the heatmap.
fn draw_colorbar(
    area: &DrawingArea<BitMapBackend, plotters::coord::Shift>,
    colormap: ColorMap,
    vmin: f64,
    vmax: f64,
) -> Result<(), Box<dyn std::error::Error>> {
    let n_steps = 100;
    let bar_width = 20;
    let margin = 10;

    let area_dim = area.get_pixel_range();
    let bar_height = (area_dim.1.end - area_dim.1.start) as f64 - 2.0 * margin as f64;
    let step_height = bar_height / n_steps as f64;

    // Draw color gradient
    for i in 0..n_steps {
        let normalized = i as f64 / (n_steps - 1) as f64;
        let color = colormap.map(1.0 - normalized); // Flip for top-to-bottom

        let y0 = (margin as f64 + i as f64 * step_height) as i32;
        let y1 = (margin as f64 + (i + 1) as f64 * step_height) as i32;

        area.draw(&Rectangle::new(
            [(margin, y0), (margin + bar_width, y1)],
            color.filled(),
        ))
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw series: {}", e)))?;
    }

    // Draw border
    area.draw(&Rectangle::new(
        [(margin, margin), (margin + bar_width, (area_dim.1.end - area_dim.1.start) as i32 - margin)],
        BLACK.stroke_width(1),
    ))?;

    // Add labels
    let font = ("sans-serif", 12).into_font();

    area.draw(&Text::new(
        format!("{:.2}", vmax),
        (margin + bar_width + 5, margin),
        font.clone().into_text_style(area)
    ))?;

    area.draw(&Text::new(
        format!("{:.2}", vmin),
        (margin + bar_width + 5, (area_dim.1.end - area_dim.1.start) as i32 - margin - 12),
        font.clone().into_text_style(area)
    ))?;

    area.draw(&Text::new(
        format!("{:.2}", (vmax + vmin) / 2.0),
        (margin + bar_width + 5, (area_dim.1.end - area_dim.1.start) as i32 / 2 - 6),
        font.into_text_style(area)
    ))?;

    Ok(())
}

/// Plot time series of design matrix regressors.
///
/// Creates line plots showing the time course of regressors in the
/// design matrix.
///
/// # Arguments
/// * `model` - Event model containing the design matrix
/// * `output_path` - Path to save the output image
/// * `term_names` - Optional list of term names to plot (None = all)
/// * `figsize` - Figure size as (width, height) in pixels
///
/// # Example
/// ```ignore
/// use fmridesign::visualization::plot_design_matrix;
///
/// // Plot all regressors
/// plot_design_matrix(&model, "timeseries.png", None, (1000, 600))?;
///
/// // Plot specific terms only
/// plot_design_matrix(&model, "condition_timeseries.png", Some(&["condition"]), (800, 400))?;
/// ```
pub fn plot_design_matrix(
    model: &EventModel,
    output_path: impl AsRef<Path>,
    term_names: Option<&[&str]>,
    figsize: (u32, u32),
) -> Result<(), ValidationError> {
    let dm = model.get_design_matrix()
        .ok_or_else(|| ValidationError::InvalidParameter(
            "Design matrix not yet generated".to_string()
        ))
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw series: {}", e)))?;

    let matrix = &dm.data;
    let time_points = &dm.row_times;

    // Select columns to plot
    let columns_to_plot: Vec<usize> = if let Some(terms) = term_names {
        // Find columns matching term names
        dm.column_names.iter()
            .enumerate()
            .filter(|(_, name)| {
                terms.iter().any(|&term| name.starts_with(term))
            })
            .map(|(i, _)| i)
            .collect()
    } else {
        // Plot all columns
        (0..matrix.ncols()).collect()
    };

    if columns_to_plot.is_empty() {
        return Err(ValidationError::InvalidParameter(
            "No columns found matching specified terms".to_string()
        ));
    }

    // Create plot
    let root = BitMapBackend::new(output_path.as_ref(), figsize)
        .into_drawing_area();

    root.fill(&WHITE)
        .map_err(|e| ValidationError::ComputationError(format!("Failed to fill background: {}", e)))?;

    // Find value range
    let mut y_min = f64::INFINITY;
    let mut y_max = f64::NEG_INFINITY;

    for &col in &columns_to_plot {
        let column = matrix.column(col);
        y_min = y_min.min(*column.iter().min_by(|a, b| a.partial_cmp(b).unwrap()).unwrap());
        y_max = y_max.max(*column.iter().max_by(|a, b| a.partial_cmp(b).unwrap()).unwrap());
    }

    // Add some padding
    let y_range = y_max - y_min;
    y_min -= y_range * 0.1;
    y_max += y_range * 0.1;

    let mut chart = ChartBuilder::on(&root)
        .caption(
            &format!("Design Matrix Time Series: {}", model.name()),
            ("sans-serif", 20).into_font()
        )
        .margin(10)
        .x_label_area_size(30)
        .y_label_area_size(40)
        .build_cartesian_2d(
            time_points[0]..time_points[time_points.len() - 1],
            y_min..y_max
        )?;

    chart.configure_mesh()
        .x_desc("Time (s)")
        .y_desc("Value")
        .draw()
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw: {}", e)))?;

    // Plot each column
    let colors = [&RED, &BLUE, &GREEN, &MAGENTA, &CYAN, &BLACK];

    for (idx, &col) in columns_to_plot.iter().enumerate() {
        let color = colors[idx % colors.len()];
        let column_data: Vec<(f64, f64)> = time_points.iter()
            .zip(matrix.column(col).iter())
            .map(|(&t, &v)| (t, v))
            .collect();

        chart.draw_series(LineSeries::new(
            column_data,
            color,
        ))
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw series: {}", e)))?
        .label(&dm.column_names[col])
        .legend(move |(x, y)| PathElement::new(vec![(x, y), (x + 10, y)], color));
    }

    // Draw legend if not too many columns
    if columns_to_plot.len() <= 10 {
        chart.configure_series_labels()
            .background_style(&WHITE.mix(0.8))
            .border_style(&BLACK)
            .draw()
        .map_err(|e| ValidationError::ComputationError(format!("Failed to draw: {}", e)))?;
    }

    root.present()
        .map_err(|e| ValidationError::ComputationError(format!("Failed to present chart: {}", e)))?;

    Ok(())
}

/// Create summary visualization of event model.
///
/// Generates both design matrix heatmap and time series plots.
///
/// # Arguments
/// * `model` - Event model to visualize
/// * `output_prefix` - Prefix for output files
/// * `config` - Visualization configuration
///
/// # Example
/// ```ignore
/// use fmridesign::visualization::{plot_model_summary, DesignMapConfig};
///
/// plot_model_summary(&model, "model", &DesignMapConfig::default())?;
/// // Creates: model_design_map.png, model_timeseries.png, model_correlation.png
/// ```
pub fn plot_model_summary(
    model: &EventModel,
    output_prefix: impl AsRef<str>,
    config: &DesignMapConfig,
) -> Result<(), ValidationError> {
    let prefix = output_prefix.as_ref();

    // Design matrix heatmap
    design_map(
        model,
        format!("{}_design_map.png", prefix),
        config,
    )?;

    // Time series plot
    plot_design_matrix(
        model,
        format!("{}_timeseries.png", prefix),
        None,
        config.figsize,
    )?;

    // Also create correlation map
    crate::visualization::correlation_map(
        model,
        format!("{}_correlation.png", prefix),
        config.figsize,
    )?;

    Ok(())
}

