//! Core event model implementation.

use crate::types::{EventSpec, EventType, Model, Array, ValidationError, ContrastSpec};
use crate::design::DesignMatrix;
use crate::sampling::SamplingFrame;
use crate::naming::{make_unique_colnames, make_column_names, level_token, continuous_token};
use crate::formula::Term;
use ndarray::{Array1, Array2};
use fmrihrf::{Hrf, hrf as hrf_lib};
use std::fmt;

/// Main event model for fMRI design.
#[derive(Debug)]
pub struct EventModel {
    /// Model name
    name: String,
    /// Event specifications
    events: Vec<Box<dyn EventSpec>>,
    /// Terms with HRF specifications
    terms: Vec<Term>,
    /// Sampling frame
    sampling_frame: Option<SamplingFrame>,
    /// Cached design matrix
    cached_design_matrix: Option<DesignMatrix>,
}

impl EventModel {
    /// Create a new event model.
    pub fn new() -> Self {
        Self {
            name: "EventModel".to_string(),
            events: Vec::new(),
            terms: Vec::new(),
            sampling_frame: None,
            cached_design_matrix: None,
        }
    }

    /// Get the number of events in the model.
    pub fn n_events(&self) -> usize {
        self.events.len()
    }

    /// Get the number of terms in the model.
    pub fn n_terms(&self) -> usize {
        self.terms.len()
    }

    /// Get event names.
    pub fn event_names(&self) -> Vec<&str> {
        self.events.iter().map(|e| e.name()).collect()
    }

    /// Get the TR (repetition time) if sampling frame is set.
    pub fn tr(&self) -> Option<f64> {
        self.sampling_frame.as_ref().map(|sf| sf.tr[0])
    }

    /// Get the number of timepoints if sampling frame is set.
    pub fn n_timepoints(&self) -> Option<usize> {
        self.sampling_frame.as_ref().map(|sf| sf.samples().len())
    }

    /// Set the model name.
    pub fn with_name<S: Into<String>>(mut self, name: S) -> Self {
        self.name = name.into();
        self
    }

    /// Add an event to the model.
    pub fn add_event(mut self, event: Box<dyn EventSpec>) -> Self {
        self.events.push(event);
        self
    }

    /// Add a term to the model.
    pub fn add_term(mut self, term: Term) -> Self {
        self.terms.push(term);
        self
    }

    /// Set the sampling frame.
    pub fn with_sampling_frame(mut self, sf: SamplingFrame) -> Self {
        self.sampling_frame = Some(sf);
        self
    }

    /// Generate the design matrix.
    pub fn generate_design_matrix(&mut self) -> Result<&DesignMatrix, ValidationError> {
        if self.cached_design_matrix.is_none() {
            // Check that we have a sampling frame
            let sampling_frame = self.sampling_frame.as_ref()
                .ok_or_else(|| ValidationError::InvalidParameter(
                    "Sampling frame must be set before generating design matrix".to_string()
                ))?;

            // Get sampling points
            let sampling_points = sampling_frame.samples();


            // Collect all design matrices from events
            let mut all_columns = Vec::new();
            let mut all_column_names = Vec::new();

            // If we have terms, use them for HRF info; otherwise just use events
            let use_terms = !self.terms.is_empty();

            for (idx, event) in self.events.iter().enumerate() {
                // Generate design matrix for this event
                let event_matrix = event.design_matrix(&ndarray::Array1::from(sampling_points.clone()))?;

                // Get column names based on event type and characteristics
                let event_name = event.name();
                let n_cols = event_matrix.ncols();

                // Generate term tag
                let term_tag = if event.name().contains(':') {
                    // For interaction terms, use the full name
                    Some(event.name())
                } else {
                    // For simple events, use just the name
                    Some(event_name)
                };

                // Generate condition tags based on event type
                let cond_tags = match event.event_type() {
                    crate::types::EventType::Categorical => {
                        // For categorical events, get level names
                        if let Some(levels) = event.levels() {
                            levels.iter()
                                .map(|level| level_token(event_name, level))
                                .collect()
                        } else {
                            // Fallback if no levels defined
                            (0..n_cols)
                                .map(|i| format!("{}_col{}", event_name, i + 1))
                                .collect()
                        }
                    }
                    crate::types::EventType::Continuous => {
                        // For covariates, just use the event name directly
                        if event.as_any().downcast_ref::<crate::covariate::CovariateEvent>().is_some() {
                            vec![event_name.to_string()]
                        } else {
                            vec![continuous_token(event_name)]
                        }
                    }
                    crate::types::EventType::Term => {
                        // For EventTerm, use its own column name generation
                        if let Some(term) = event.as_any().downcast_ref::<crate::events::EventTerm>() {
                            term.get_column_names()
                        } else {
                            // Fallback
                            (0..n_cols)
                                .map(|i| format!("{}_col{}", event_name, i + 1))
                                .collect()
                        }
                    }
                    crate::types::EventType::Basis => {
                        // For basis events, use basis function names
                        if let Some(basis_event) = event.as_any().downcast_ref::<crate::events::EventBasis>() {
                            basis_event.basis_names()
                        } else {
                            // Fallback - numbered basis columns
                            (0..n_cols)
                                .map(|i| format!("{}_basis{}", event_name, i + 1))
                                .collect()
                        }
                    }
                    _ => {
                        // For other types, just use numbered columns
                        (0..n_cols)
                            .map(|i| format!("col{}", i + 1))
                            .collect()
                    }
                };

                // Generate column names using the naming functions
                let col_names = make_column_names(term_tag, &cond_tags, 1);

                // Check if this event has HRF specification in terms
                // But skip HRF for covariates
                let is_covariate = event.as_any()
                    .downcast_ref::<crate::covariate::CovariateEvent>()
                    .is_some();

                let hrf_spec = if use_terms && idx < self.terms.len() && !is_covariate {
                    self.terms[idx].hrf.as_ref()
                } else {
                    None
                };

                // Add columns with optional HRF convolution
                for i in 0..n_cols {
                    let mut column = event_matrix.column(i).to_owned();

                    // Apply HRF convolution if specified
                    if let Some(crate::formula::HrfSpec::Named(hrf_name)) = hrf_spec {
                        column = self.convolve_with_hrf(&column, hrf_name)?;
                    }

                    all_columns.push(column);
                    all_column_names.push(col_names[i].clone());
                }
            }

            // Stack columns horizontally
            if all_columns.is_empty() {
                return Err(ValidationError::InvalidParameter(
                    "No events to generate design matrix from".to_string()
                ));
            }

            let n_timepoints = all_columns[0].len();
            let n_cols = all_columns.len();
            let mut design_matrix = Array2::zeros((n_timepoints, n_cols));

            for (i, col) in all_columns.iter().enumerate() {
                design_matrix.column_mut(i).assign(col);
            }

            // Ensure unique column names
            let unique_names = make_unique_colnames(&all_column_names);

            // Create design matrix with row times
            let dm = DesignMatrix::with_times(
                design_matrix,
                unique_names,
                ndarray::Array1::from(sampling_points),
            );

            self.cached_design_matrix = Some(dm);
        }

        Ok(self.cached_design_matrix.as_ref().unwrap())
    }

    /// Apply HRF convolution to a design matrix column.
    fn convolve_with_hrf(&self, column: &Array1<f64>, hrf_name: &str) -> Result<Array1<f64>, ValidationError> {
        // Get the TR from sampling frame
        let sf = self.sampling_frame.as_ref()
            .ok_or_else(|| ValidationError::InvalidParameter("No sampling frame".to_string()))?;
        let tr = sf.tr[0];  // Use first TR value

        // Create HRF based on name  
        let hrf = match hrf_name {
            "canonical" | "spm_canonical" => hrf_lib::spm_canonical(None, None, None, None, None, None),
            "gamma" | "spm_gamma" => hrf_lib::gamma_hrf(6.0, 1.0, None),
            _ => return Err(ValidationError::InvalidParameter(format!("Unknown HRF: {}", hrf_name))),
        };

        // Generate HRF kernel
        let hrf_duration = 32.0; // seconds
        let hrf_samples = (hrf_duration / tr) as usize;
        let t = Array1::linspace(0.0, hrf_duration, hrf_samples);
        let hrf_values = hrf.evaluate(&t)
            .map_err(|e| ValidationError::ComputationError(format!("HRF evaluation failed: {}", e)))?;

        // Extract first column if multiple basis functions
        let kernel = hrf_values.column(0);

        // Perform convolution using our discrete_convolve function
        let convolved = crate::convolve::discrete_convolve(column, &kernel.to_owned());

        // Trim to original length
        Ok(convolved.slice(ndarray::s![..column.len()]).to_owned())
    }

    /// Get a summary of the model.
    pub fn summary(&self) -> String {
        let mut lines = vec![
            format!("EventModel: {}", self.name),
            format!("  Events: {} ({})", 
                self.n_events(), 
                self.event_names().join(", ")
            ),
            format!("  Terms: {}", self.n_terms()),
        ];

        // Add sampling info if available
        if let Some(ref sf) = self.sampling_frame {
            lines.push(format!(
                "  Sampling: TR={}s, {} timepoints",
                sf.tr[0],
                sf.samples().len()
            ));
        }

        // Add design matrix info if generated
        if let Some(ref dm) = self.cached_design_matrix {
            lines.push(format!(
                "  Design matrix: {} × {}",
                dm.data.nrows(),
                dm.data.ncols()
            ));
        }

        lines.join("\n")
    }

    /// Get column indices for each term.
    ///
    /// Returns a map from term names to their column indices in the design matrix.
    pub fn column_indices(&self) -> Result<std::collections::HashMap<String, Vec<usize>>, ValidationError> {
        let dm = self.cached_design_matrix.as_ref()
            .ok_or_else(|| ValidationError::InvalidParameter(
                "Design matrix not yet generated. Call generate_design_matrix() first.".to_string()
            ))?;

        let mut indices = std::collections::HashMap::new();

        // Group columns by term
        // This is a simplified version - in practice we'd need to track which columns
        // belong to which terms during design matrix generation
        for (idx, name) in dm.column_names.iter().enumerate() {
            // Extract term name from column name (simplified logic)
            let term_name = if let Some(pos) = name.find('.') {
                name[..pos].to_string()
            } else {
                name.clone()
            };

            indices.entry(term_name)
                .or_insert_with(Vec::new)
                .push(idx);
        }

        Ok(indices)
    }

    /// Get shortened column names.
    pub fn shortnames(&self) -> Vec<String> {
        if let Some(ref dm) = self.cached_design_matrix {
            // Create shortened versions of column names
            dm.column_names.iter()
                .map(|name| {
                    // Simple shortening: take last part after dot or underscore
                    if let Some(pos) = name.rfind('.') {
                        name[pos + 1..].to_string()
                    } else if let Some(pos) = name.rfind('_') {
                        name[pos + 1..].to_string()
                    } else {
                        name.clone()
                    }
                })
                .collect()
        } else {
            Vec::new()
        }
    }

    /// Get long column names (alias for column_names).
    pub fn longnames(&self) -> Vec<String> {
        self.column_names().to_vec()
    }

    /// Get condition names from categorical events.
    pub fn conditions(&self) -> Vec<String> {
        let mut conditions = Vec::new();

        for event in &self.events {
            if event.event_type() == EventType::Categorical {
                if let Some(levels) = event.levels() {
                    conditions.extend(levels.iter().cloned());
                }
            }
        }

        conditions.sort();
        conditions.dedup();
        conditions
    }

    /// Get the design matrix (public access).
    pub fn get_design_matrix(&self) -> Option<&DesignMatrix> {
        self.cached_design_matrix.as_ref()
    }

    /// Get the model name.
    pub fn name(&self) -> &str {
        &self.name
    }

    /// Get information about the model as a formatted string.
    pub fn info(&self) -> String {
        let mut lines = vec![
            format!("=== {} ===", self.name),
            format!(""),
            format!("Events ({})", self.n_events()),
        ];

        // List events with their types
        for event in &self.events {
            lines.push(format!("  - {} ({:?})", event.name(), event.event_type()));
        }

        lines.push(format!(""));
        lines.push(format!("Terms ({})", self.n_terms()));

        // List terms with HRF info
        for term in &self.terms {
            let hrf_str = if let Some(ref hrf) = term.hrf {
                match hrf {
                    crate::formula::HrfSpec::Named(name) => format!(" [HRF: {}]", name),
                    crate::formula::HrfSpec::Custom(_) => " [HRF: custom]".to_string(),
                }
            } else {
                "".to_string()
            };

            lines.push(format!("  - {}{}", term.effective_name(), hrf_str));
        }

        // Add sampling and design matrix info
        if let Some(ref sf) = self.sampling_frame {
            lines.push(format!(""));
            lines.push(format!("Sampling"));
            lines.push(format!("  TR: {} s", sf.tr[0]));
            lines.push(format!("  Duration: {} s", sf.samples().last().unwrap_or(&0.0)));
            lines.push(format!("  Timepoints: {}", sf.samples().len()));
        }

        if let Some(ref dm) = self.cached_design_matrix {
            lines.push(format!(""));
            lines.push(format!("Design Matrix"));
            lines.push(format!("  Shape: {} × {}", dm.data.nrows(), dm.data.ncols()));
            lines.push(format!("  Columns: {}", dm.column_names.join(", ")));
        }

        lines.join("\n")
    }
}

impl Default for EventModel {
    fn default() -> Self {
        Self::new()
    }
}

impl fmt::Display for EventModel {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(f, "{}", self.summary())
    }
}

impl Model for EventModel {
    fn design_matrix(&self) -> &Array {
        if let Some(ref dm) = self.cached_design_matrix {
            &dm.data
        } else {
            panic!("Design matrix not yet generated. Call generate_design_matrix() first.");
        }
    }

    fn column_names(&self) -> &[String] {
        if let Some(ref dm) = self.cached_design_matrix {
            &dm.column_names
        } else {
            panic!("Design matrix not yet generated. Call generate_design_matrix() first.");
        }
    }

    fn add_contrast(&self, contrast: Box<dyn ContrastSpec>) -> Result<(), ValidationError> {
        // Validate contrast against current design matrix
        if let Some(ref dm) = self.cached_design_matrix {
            let weights = contrast.compute_weights(&dm.column_names)?;

            // Check that weights have correct length
            if weights.len() != dm.column_names.len() {
                return Err(ValidationError::LengthMismatch {
                    expected: dm.column_names.len(),
                    actual: weights.len(),
                });
            }

            // TODO: Store contrast for later use
            println!("Added contrast '{}' with {} weights", contrast.name(), weights.len());

            Ok(())
        } else {
            Err(ValidationError::InvalidParameter(
                "Design matrix must be generated before adding contrasts".to_string()
            ))
        }
    }
}

// DataFrame-like structure for event data
use std::collections::HashMap;

/// Simple DataFrame for event data
#[derive(Debug, Clone)]
pub struct DataFrame {
    /// Numeric columns
    pub columns: HashMap<String, Vec<f64>>,
    /// String columns
    pub str_columns: HashMap<String, Vec<String>>,
}

impl DataFrame {
    /// Create new DataFrame
    pub fn new() -> Self {
        Self {
            columns: HashMap::new(),
            str_columns: HashMap::new(),
        }
    }

    /// Get numeric column
    pub fn get_column(&self, name: &str) -> Option<&Vec<f64>> {
        self.columns.get(name)
    }

    /// Get string column
    pub fn get_str_column(&self, name: &str) -> Option<&Vec<String>> {
        self.str_columns.get(name)
    }

    /// Number of rows
    pub fn len(&self) -> usize {
        self.columns.values()
            .map(|v| v.len())
            .chain(self.str_columns.values().map(|v| v.len()))
            .max()
            .unwrap_or(0)
    }

    /// Check if empty
    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }
}

impl Default for DataFrame {
    fn default() -> Self {
        Self::new()
    }
}

/// Create an event model from a formula and data.
///
/// This is the main entry point for creating event models from a formula
/// specification and data.
///
/// # Arguments
/// * `formula` - Formula string (e.g., "condition", "hrf(condition)")
/// * `data` - DataFrame containing event data
/// * `tr` - Repetition time in seconds
/// * `n_scans` - Number of scans
///
/// # Example
/// ```ignore
/// let model = event_model("condition", &data, 2.0, 100)?;
/// ```
pub fn event_model(
    formula: &str,
    data: &DataFrame,
    tr: f64,
    n_scans: usize,
) -> Result<EventModel, ValidationError> {
    use crate::formula::parse_formula;
    use crate::sampling::uniform_sampling_frame;
    use crate::events::{EventFactor, EventVariable};

    // Create sampling frame
    let sampling_frame = uniform_sampling_frame(n_scans, tr, None)
        .map_err(|e| ValidationError::InvalidParameter(format!("Failed to create sampling frame: {}", e)))?;

    // Parse formula to get terms
    let terms = parse_formula(formula)?;


    // Create events from data based on terms
    let mut model = EventModel::new()
        .with_sampling_frame(sampling_frame);

    for term in terms {
        // Check if this is a trialwise term
        if crate::trialwise::is_trialwise_term(&term) {
            // Handle trialwise terms
            let config = crate::trialwise::get_trialwise_config(&term)
                .ok_or_else(|| ValidationError::InvalidParameter("Invalid trialwise configuration".to_string()))?;

            // Get onset information from data
            let onsets = data.get_column("onset")
                .ok_or_else(|| ValidationError::InvalidParameter("Missing 'onset' column for trialwise".to_string()))?;

            let default_durations = vec![0.0; onsets.len()];
            let durations = data.get_column("duration")
                .unwrap_or(&default_durations);

            // Create trial factor
            let trial_factor = crate::trialwise::create_trial_factor(
                onsets.len(),
                Some(&ndarray::Array1::from(onsets.clone())),
                Some(&ndarray::Array1::from(durations.clone())),
                &config.label,
            )?;

            // Create EventTerm with the trial factor
            let event_term = crate::events::EventTerm::new(
                vec![Box::new(trial_factor)],
                false,  // Not an interaction
            )?;

            // Handle add_sum option for trialwise - we need to handle this differently
            // For now, store the config in the event term for later processing
            // TODO: Implement proper add_sum handling

            // Mark it as trialwise for special handling
            // We'll need to add this capability to EventTerm
            // For now, add as regular event
            model = model.add_event(Box::new(event_term));

            // Add the term with HRF spec
            model = model.add_term(term.clone());

        } else if crate::covariate::is_covariate_term(&term) {
            // Handle covariate terms
            let config = crate::covariate::get_covariate_config(&term)
                .ok_or_else(|| ValidationError::InvalidParameter("Invalid covariate configuration".to_string()))?;

            // Get the number of timepoints from the sampling frame
            let n_timepoints = n_scans;

            // Create covariate events
            let covariate_events = crate::covariate::create_covariate_events(
                data,
                &config.covariates,
                n_timepoints,
                config.prefix.as_deref(),
            )?;

            // Add each covariate as an event
            for cov_event in covariate_events {
                model = model.add_event(Box::new(cov_event));
            }

            // Add the term (without HRF since covariates aren't convolved)
            model = model.add_term(term.clone());

        } else if term.events.len() == 1 && term.events[0] == "_trialwise_placeholder_" {
            // Skip placeholder terms, they've been handled above
            continue;
        } else if term.events.len() == 1 {
            // Single event
            let event_name = &term.events[0];

            // Look for the event in the data
            if let Some(numeric_col) = data.get_column(event_name) {
                // Continuous variable
                let onsets = data.get_column("onset")
                    .ok_or_else(|| ValidationError::InvalidParameter("Missing 'onset' column".to_string()))?;

                let default_durations = vec![0.0; onsets.len()];
                let durations = data.get_column("duration")
                    .unwrap_or(&default_durations);

                // Check if this has a basis function
                if let Some(crate::formula::TermParam::Number(degree)) = term.params.get("poly_degree") {
                    // Create EventBasis with polynomial expansion
                    let basis = crate::basis::Poly::new(*degree as usize);
                    let event = crate::events::EventBasis::new(
                        event_name,
                        onsets.clone(),
                        numeric_col.clone(),
                        Box::new(basis),
                        durations.clone(),
                    )?;
                    model = model.add_event(Box::new(event));
                } else if let Some(crate::formula::TermParam::Number(df)) = term.params.get("bs_df") {
                    // Create EventBasis with B-spline expansion
                    let basis = crate::basis::Bs::new(*df as usize);
                    let event = crate::events::EventBasis::new(
                        event_name,
                        onsets.clone(),
                        numeric_col.clone(),
                        Box::new(basis),
                        durations.clone(),
                    )?;
                    model = model.add_event(Box::new(event));
                } else if term.params.contains_key("scale_center") || term.params.contains_key("scale_scale") {
                    // Create scaled/standardized variable
                    // For now, just apply centering/scaling to the values
                    let center = term.params.get("scale_center")
                        .and_then(|p| if let crate::formula::TermParam::Number(n) = p { Some(*n != 0.0) } else { None })
                        .unwrap_or(true);
                    let scale = term.params.get("scale_scale")
                        .and_then(|p| if let crate::formula::TermParam::Number(n) = p { Some(*n != 0.0) } else { None })
                        .unwrap_or(true);

                    let mut scaled_values = numeric_col.clone();
                    if center || scale {
                        let mean = if center {
                            scaled_values.iter().sum::<f64>() / scaled_values.len() as f64
                        } else {
                            0.0
                        };

                        if center {
                            for v in &mut scaled_values {
                                *v -= mean;
                            }
                        }

                        if scale {
                            let variance = scaled_values.iter()
                                .map(|v| v * v)
                                .sum::<f64>() / scaled_values.len() as f64;
                            let std_dev = variance.sqrt();

                            if std_dev > 0.0 {
                                for v in &mut scaled_values {
                                    *v /= std_dev;
                                }
                            }
                        }
                    }

                    let event = EventVariable::new(
                        event_name,
                        onsets.clone(),
                        scaled_values,
                        durations.clone(),
                    )?;
                    model = model.add_event(Box::new(event));
                } else {
                    // Regular continuous variable
                    let event = EventVariable::new(
                        event_name,
                        onsets.clone(),
                        numeric_col.clone(),
                        durations.clone(),
                    )?;
                    model = model.add_event(Box::new(event));
                }
            } else if let Some(str_col) = data.get_str_column(event_name) {
                // Categorical variable
                let onsets = data.get_column("onset")
                    .ok_or_else(|| ValidationError::InvalidParameter("Missing 'onset' column".to_string()))?;

                let default_durations = vec![0.0; onsets.len()];
                let durations = data.get_column("duration")
                    .unwrap_or(&default_durations);

                // Convert String to &str for EventFactor
                let values: Vec<&str> = str_col.iter().map(|s| s.as_str()).collect();
                let event = EventFactor::new(
                    event_name,
                    onsets.clone(),
                    values,
                    durations.clone(),
                )?;

                model = model.add_event(Box::new(event));
            } else {
                return Err(ValidationError::InvalidParameter(
                    format!("Event '{}' not found in data", event_name)
                ));
            }
        } else {
            // Interaction term - create EventTerm
            let mut sub_events: Vec<Box<dyn EventSpec>> = Vec::new();

            for event_name in &term.events {
                if let Some(numeric_col) = data.get_column(event_name) {
                    // Continuous variable
                    let onsets = data.get_column("onset")
                        .ok_or_else(|| ValidationError::InvalidParameter("Missing 'onset' column".to_string()))?;

                    let default_durations = vec![0.0; onsets.len()];
                    let durations = data.get_column("duration")
                        .unwrap_or(&default_durations);

                    let event = EventVariable::new(
                        event_name,
                        onsets.clone(),
                        numeric_col.clone(),
                        durations.clone(),
                    )?;

                    sub_events.push(Box::new(event));
                } else if let Some(str_col) = data.get_str_column(event_name) {
                    // Categorical variable
                    let onsets = data.get_column("onset")
                        .ok_or_else(|| ValidationError::InvalidParameter("Missing 'onset' column".to_string()))?;

                    let default_durations = vec![0.0; onsets.len()];
                    let durations = data.get_column("duration")
                        .unwrap_or(&default_durations);

                    let values: Vec<&str> = str_col.iter().map(|s| s.as_str()).collect();
                    let event = EventFactor::new(
                        event_name,
                        onsets.clone(),
                        values,
                        durations.clone(),
                    )?;

                    sub_events.push(Box::new(event));
                } else {
                    return Err(ValidationError::InvalidParameter(
                        format!("Event '{}' not found in data", event_name)
                    ));
                }
            }

            // Create EventTerm for interaction
            let event_term = crate::events::EventTerm::new(sub_events, true)?;
            model = model.add_event(Box::new(event_term));
        }

        // Store the term for HRF processing (but not for trialwise, it was already added)
        if !crate::trialwise::is_trialwise_term(&term) {
            model.terms.push(term.clone());
        }

        // TODO: Handle basis functions
    }

    Ok(model)
}

