//! Spline basis functions.

use crate::types::{BasisFunction, Array, Vector, ValidationError};
use ndarray::{Array1, Array2, ArrayView1};

/// B-spline basis functions.
#[derive(Debug, Clone)]
pub struct BSplineBasis {
    name: String,
    df: Option<usize>,
    knots: Option<Vec<f64>>,
    degree: usize,
    intercept: bool,
    boundary_knots: Option<(f64, f64)>,
    // Computed during first evaluation
    computed_knots: Option<Vec<f64>>,
    boundary: Option<(f64, f64)>,
}

impl BSplineBasis {
    /// Create new B-spline basis with degrees of freedom.
    pub fn new(df: usize) -> Self {
        Self {
            name: format!("bs{}", df),
            df: Some(df),
            knots: None,
            degree: 3, // Cubic by default
            intercept: true,
            boundary_knots: None,
            computed_knots: None,
            boundary: None,
        }
    }

    /// Create B-spline basis with specified knots.
    pub fn with_knots(knots: Vec<f64>) -> Self {
        let df = knots.len() + 3 + 1; // degree + intercept
        Self {
            name: format!("bs{}", df),
            df: Some(df),
            knots: Some(knots),
            degree: 3,
            intercept: true,
            boundary_knots: None,
            computed_knots: None,
            boundary: None,
        }
    }

    /// Set the degree of the splines.
    pub fn with_degree(mut self, degree: usize) -> Self {
        self.degree = degree;
        if let Some(knots) = &self.knots {
            self.df = Some(knots.len() + degree + if self.intercept { 1 } else { 0 });
        }
        self
    }

    /// Set whether to include intercept.
    pub fn with_intercept(mut self, intercept: bool) -> Self {
        self.intercept = intercept;
        if let Some(knots) = &self.knots {
            self.df = Some(knots.len() + self.degree + if intercept { 1 } else { 0 });
        }
        self
    }

    /// Set boundary knots.
    pub fn with_boundary_knots(mut self, min: f64, max: f64) -> Self {
        self.boundary_knots = Some((min, max));
        self
    }

    /// Set custom name.
    pub fn with_name(mut self, name: String) -> Self {
        self.name = name;
        self
    }

    /// Setup knot locations based on data.
    fn setup_knots(&mut self, x: &ArrayView1<f64>) -> Result<(), ValidationError> {
        // Determine boundaries
        if self.boundary_knots.is_none() {
            let x_min = x.iter().cloned().fold(f64::INFINITY, f64::min);
            let x_max = x.iter().cloned().fold(f64::NEG_INFINITY, f64::max);
            let buffer = 0.01 * (x_max - x_min);
            self.boundary = Some((x_min - buffer, x_max + buffer));
        } else {
            self.boundary = self.boundary_knots;
        }

        // Determine interior knots
        if self.knots.is_none() {
            let df = self.df.ok_or_else(|| {
                ValidationError::InvalidParameter("Either df or knots must be specified".to_string())
            })?;

            // Compute number of interior knots
            // For B-splines: df = n_interior_knots + degree + 1
            let n_interior = df.saturating_sub(self.degree + 1);

            if n_interior > 0 {
                // Equal spacing in quantiles
                let mut sorted_x = x.to_vec();
                sorted_x.sort_by(|a, b| a.partial_cmp(b).unwrap());

                let mut interior_knots = Vec::with_capacity(n_interior);
                for i in 1..=n_interior {
                    let quantile = i as f64 / (n_interior + 1) as f64;
                    let idx = (quantile * (sorted_x.len() - 1) as f64) as usize;
                    interior_knots.push(sorted_x[idx]);
                }
                self.knots = Some(interior_knots);
            } else {
                self.knots = Some(Vec::new());
            }
        }

        // Create full knot sequence
        let boundary = self.boundary.unwrap();
        let interior_knots = self.knots.as_ref().unwrap();

        let mut full_knots = Vec::new();
        // Add boundary knots (degree + 1 times)
        for _ in 0..=self.degree {
            full_knots.push(boundary.0);
        }
        // Add interior knots
        full_knots.extend(interior_knots);
        // Add boundary knots (degree + 1 times)
        for _ in 0..=self.degree {
            full_knots.push(boundary.1);
        }

        self.computed_knots = Some(full_knots);
        Ok(())
    }

    /// Evaluate B-spline basis function i at points x.
    fn evaluate_basis_function(&self, x: &ArrayView1<f64>, i: usize) -> Result<Array1<f64>, ValidationError> {
        // This is a simplified implementation
        // For a full implementation, we would need to implement Cox-de Boor recursion
        // or use a proper spline library

        let knots = self.computed_knots.as_ref()
            .ok_or_else(|| ValidationError::InvalidParameter("Knots not initialized".to_string()))?;

        let n = x.len();
        let mut result = Array1::zeros(n);

        // Simplified B-spline evaluation
        // This is a placeholder - real implementation would use Cox-de Boor algorithm
        let boundary = self.boundary.unwrap();

        for j in 0..n {
            let xi = x[j];

            // Check if within boundaries
            if xi < boundary.0 || xi > boundary.1 {
                result[j] = 0.0;
                continue;
            }

            // Simple triangular basis as placeholder
            // Real B-spline would use proper basis computation
            let n_basis = self.nbasis();
            let width = (boundary.1 - boundary.0) / n_basis as f64;
            let center = boundary.0 + (i as f64 + 0.5) * width;

            let dist = (xi - center).abs();
            if dist < width {
                result[j] = 1.0 - dist / width;
            } else {
                result[j] = 0.0;
            }
        }

        Ok(result)
    }
}

impl BasisFunction for BSplineBasis {
    fn name(&self) -> &str {
        &self.name
    }

    fn nbasis(&self) -> usize {
        self.df.unwrap_or_else(|| {
            self.knots.as_ref().map(|k| k.len()).unwrap_or(0) + self.degree + if self.intercept { 1 } else { 0 }
        })
    }

    fn evaluate(&self, x: &ArrayView1<f64>) -> Result<Array, ValidationError> {
        // Clone self to allow mutation for setup_knots
        let mut self_mut = self.clone();

        // Setup knots if not already done
        if self_mut.computed_knots.is_none() {
            self_mut.setup_knots(x)?;
        }

        let n = x.len();
        let n_basis = self.nbasis();
        let mut basis = Array2::zeros((n, n_basis));

        // Evaluate each basis function
        for i in 0..n_basis {
            let col = self_mut.evaluate_basis_function(x, i)?;
            basis.column_mut(i).assign(&col);
        }

        Ok(basis)
    }

    fn predict(&self, x: &ArrayView1<f64>, coef: Option<&ArrayView1<f64>>) -> Result<Vector, ValidationError> {
        let basis = self.evaluate(x)?;

        if let Some(c) = coef {
            if c.len() != self.nbasis() {
                return Err(ValidationError::LengthMismatch {
                    expected: self.nbasis(),
                    actual: c.len(),
                });
            }
            Ok(basis.dot(c))
        } else {
            Ok(basis.column(0).to_owned())
        }
    }
}

/// Natural cubic spline basis functions.
#[derive(Debug, Clone)]
pub struct NaturalSplineBasis {
    inner: BSplineBasis,
}

impl NaturalSplineBasis {
    /// Create new natural spline basis with degrees of freedom.
    pub fn new(df: usize) -> Self {
        Self {
            inner: BSplineBasis::new(df)
                .with_degree(3)
                .with_name(format!("ns{}", df)),
        }
    }

    /// Create natural spline basis with specified knots.
    pub fn with_knots(knots: Vec<f64>) -> Self {
        let df = knots.len() + 3 + 1;
        Self {
            inner: BSplineBasis::with_knots(knots)
                .with_degree(3)
                .with_name(format!("ns{}", df)),
        }
    }

    /// Set whether to include intercept.
    pub fn with_intercept(mut self, intercept: bool) -> Self {
        self.inner = self.inner.with_intercept(intercept);
        self
    }

