//! Direct convolution functions for events with HRF.

use ndarray::{Array1, Array2};
use crate::types::{EventSpec, Array, ValidationError};
use crate::events::{EventFactor, EventVariable, EventMatrix, EventBasis, EventTerm};
use fmrihrf::{Hrf, hrf as hrf_lib};

/// Options for convolution
#[derive(Debug, Clone)]
pub struct ConvolveOptions {
    /// Sampling rate in Hz (default 1.0)
    pub sampling_rate: f64,
    /// Total duration in seconds (if None, computed from events)
    pub total_duration: Option<f64>,
    /// HRF duration for truncation (default 32.0)
    pub hrf_duration: f64,
    /// Temporal precision for convolution (default 0.1)
    pub precision: f64,
    /// Convolution method ('conv', 'fft', 'direct')
    pub method: String,
}

impl Default for ConvolveOptions {
    fn default() -> Self {
        Self {
            sampling_rate: 1.0,
            total_duration: None,
            hrf_duration: 32.0,
            precision: 0.1,
            method: "conv".to_string(),
        }
    }
}

/// Trait for objects that can be convolved with an HRF
pub trait Convolvable {
    /// Convolve with HRF
    fn convolve(&self, hrf: &dyn Hrf, options: &ConvolveOptions) -> Result<Array, ValidationError>;
}

/// Get HRF values for convolution
pub fn get_hrf_array(hrf: &dyn Hrf, sampling_rate: f64, duration: f64) -> Result<Array1<f64>, ValidationError> {
    let t = Array1::linspace(0.0, duration, ((duration * sampling_rate) as usize) + 1);
    let hrf_values = hrf.evaluate(&t)
        .map_err(|e| ValidationError::ComputationError(format!("HRF evaluation failed: {}", e)))?;

    // If HRF has multiple basis functions, just use the first one for now
    if hrf_values.ncols() > 1 {
        Ok(hrf_values.column(0).to_owned())
    } else {
        Ok(hrf_values.column(0).to_owned())
    }
}

/// Convolve impulses with HRF using discrete convolution
fn convolve_impulses(
    times: &Array1<f64>,
    values: &Array1<f64>,
    durations: &Array1<f64>,
    hrf_array: &Array1<f64>,
    sampling_rate: f64,
    total_duration: f64,
) -> Result<Array1<f64>, ValidationError> {
    // Create impulse train
    let n_samples = (total_duration * sampling_rate) as usize;
    let mut signal = Array1::zeros(n_samples);

    for i in 0..times.len() {
        let t = times[i];
        let v = values[i];
        let d = durations[i];

        // Convert to samples
        let start_idx = (t * sampling_rate) as usize;
        let duration_samples = ((d * sampling_rate) as usize).max(1);

        // Add boxcar
        if start_idx < n_samples {
            let end_idx = (start_idx + duration_samples).min(n_samples);
            for idx in start_idx..end_idx {
                signal[idx] += v;
            }
        }
    }

    // Perform convolution
    let convolved = discrete_convolve(&signal, hrf_array);

    // Trim to original length
    Ok(convolved.slice(ndarray::s![..n_samples]).to_owned())
}

/// Discrete convolution (same mode)
pub fn discrete_convolve(signal: &Array1<f64>, kernel: &Array1<f64>) -> Array1<f64> {
    let signal_len = signal.len();
    let kernel_len = kernel.len();

    if signal_len == 0 || kernel_len == 0 {
        return Array1::zeros(signal_len);
    }

    // Standard discrete convolution
    let mut result = Array1::zeros(signal_len);

    for i in 0..signal_len {
        let mut sum = 0.0;
        for j in 0..kernel_len.min(i + 1) {
            if i >= j {
                sum += signal[i - j] * kernel[j];
            }
        }
        result[i] = sum;
    }

    result
}

impl Convolvable for EventFactor {
    fn convolve(&self, hrf: &dyn Hrf, options: &ConvolveOptions) -> Result<Array, ValidationError> {
        // Get HRF array
        let hrf_array = get_hrf_array(hrf, options.sampling_rate, options.hrf_duration)?;

        // Determine total duration
        let max_time = self.onsets().iter()
            .zip(self.durations().iter())
            .map(|(o, d)| o + d)
            .fold(f64::NEG_INFINITY, f64::max);
        let total_duration = options.total_duration.unwrap_or(max_time + options.hrf_duration);

        // Create result matrix
        let n_samples = (total_duration * options.sampling_rate) as usize;
        let n_levels = self.n_levels();
        let mut convolved = Array2::zeros((n_samples, n_levels));

        // Convolve each level separately
        for (i, level) in self.levels.iter().enumerate() {
            // Get events for this level
            let level_indices: Vec<usize> = self.values.iter()
                .enumerate()
                .filter(|(_, v)| *v == level)
                .map(|(idx, _)| idx)
                .collect();

            if !level_indices.is_empty() {
                let level_onsets: Array1<f64> = level_indices.iter()
                    .map(|&idx| self.onsets()[idx])
                    .collect();
                let level_durations: Array1<f64> = level_indices.iter()
                    .map(|&idx| self.durations()[idx])
                    .collect();
                let level_values = Array1::ones(level_indices.len());

                let conv = convolve_impulses(
                    &level_onsets,
                    &level_values,
                    &level_durations,
                    &hrf_array,
                    options.sampling_rate,
                    total_duration,
                )?;

                convolved.column_mut(i).assign(&conv);
            }
        }

        Ok(convolved)
    }
}

impl Convolvable for EventVariable {
    fn convolve(&self, hrf: &dyn Hrf, options: &ConvolveOptions) -> Result<Array, ValidationError> {
        // Get HRF array
        let hrf_array = get_hrf_array(hrf, options.sampling_rate, options.hrf_duration)?;

        // Determine total duration
        let max_time = self.onsets().iter()
            .zip(self.durations().iter())
            .map(|(o, d)| o + d)
            .fold(f64::NEG_INFINITY, f64::max);
        let total_duration = options.total_duration.unwrap_or(max_time + options.hrf_duration);

        // Convolve continuous values
        let convolved = convolve_impulses(
            self.onsets(),
            &self.values,
            self.durations(),
            &hrf_array,
            options.sampling_rate,
            total_duration,
        )?;

        // Return as 2D array with single column
        Ok(convolved.insert_axis(ndarray::Axis(1)))
    }
}

impl Convolvable for EventMatrix {
    fn convolve(&self, hrf: &dyn Hrf, options: &ConvolveOptions) -> Result<Array, ValidationError> {
        // Get HRF array
        let hrf_array = get_hrf_array(hrf, options.sampling_rate, options.hrf_duration)?;

        // Determine total duration
        let max_time = self.onsets().iter()
            .zip(self.durations().iter())
            .map(|(o, d)| o + d)
            .fold(f64::NEG_INFINITY, f64::max);
        let total_duration = options.total_duration.unwrap_or(max_time + options.hrf_duration);

        // Convolve each column
        let n_samples = (total_duration * options.sampling_rate) as usize;
        let n_cols = self.n_columns();
        let mut convolved = Array2::zeros((n_samples, n_cols));

        for i in 0..n_cols {
            if let Some(col_values) = self.get_column(i) {
                let conv = convolve_impulses(
                    self.onsets(),
                    &col_values,
                    self.durations(),
                    &hrf_array,
                    options.sampling_rate,
                    total_duration,
                )?;

                convolved.column_mut(i).assign(&conv);
            }
        }

        Ok(convolved)
    }
}

impl Convolvable for EventBasis {
    fn convolve(&self, _hrf: &dyn Hrf, _options: &ConvolveOptions) -> Result<Array, ValidationError> {
        // EventBasis convolution is more complex as it requires the sampling frame
        // This should be handled at a higher level in the design matrix generation
        Err(ValidationError::InvalidParameter(
            "Direct convolution of EventBasis requires sampling_frame. \
             Use EventModel.design_matrix() instead.".to_string()
        ))
    }
}

impl Convolvable for EventTerm {
    fn convolve(&self, _hrf: &dyn Hrf, _options: &ConvolveOptions) -> Result<Array, ValidationError> {
        // EventTerm convolution should be handled by first generating the design matrix
        // then convolving the result
        Err(ValidationError::InvalidParameter(
            "Direct convolution of EventTerm is not implemented. \
             Generate design matrix first.".to_string()
        ))
    }
}

/// Convolve a generic event with HRF
pub fn convolve(event: &dyn EventSpec, hrf: &dyn Hrf, options: &ConvolveOptions) -> Result<Array, ValidationError> {
    // This would require dynamic dispatch based on event type
    // For now, return an error
    Err(ValidationError::InvalidParameter(
        "Generic convolution not yet implemented. Use specific event types.".to_string()
    ))
}

