    57→    /// Polynomial basis
    58→    Polynomial,
    59→    /// B-spline basis
    60→    BSpline,
    61→    /// Natural spline basis (simplified as B-spline)
    62→    NaturalSpline,
    63→}
    64→
    65→/// Type of intercept to include
    66→#[derive(Debug, Clone, Copy, PartialEq)]
    67→pub enum InterceptType {
