    93→            match basis {
    94→                BasisType::Constant => "constant",
    95→                BasisType::Polynomial => "poly",
    96→                BasisType::BSpline => "bs",
    97→                BasisType::NaturalSpline => "ns",
    98→            },
    99→            degree
   100→        );
   101→        
   102→        Self {
   103→            degree: if basis == BasisType::Constant { 1 } else { degree },
   104→            basis,
