   116→    /// Design matrix for this term
   117→    pub design_matrix: Array2<f64>,
   118→    /// Column indices for each block
   119→    pub col_indices: Vec<Vec<usize>>,
   120→    /// Row indices for each block
   121→    pub row_indices: Vec<Vec<usize>>,
   122→    /// Column names
   123→    pub column_names: Vec<String>,
   124→}
   125→
   126→impl BaselineTerm {
   127→    /// Get design matrix for specific blocks
   128→    pub fn get_block_matrix(&self, block_ids: Option<&[usize]>, all_rows: bool) -> Array2<f64> {
   129→        if block_ids.is_none() {
   130→            return self.design_matrix.clone();
   131→        }
   132→        
   133→        let block_ids = block_ids.unwrap();
   134→        
   135→        // Get column indices for requested blocks
   136→        let mut col_idx = Vec::new();
   137→        for &bid in block_ids {
   138→            if bid < self.col_indices.len() {
   139→                col_idx.extend(&self.col_indices[bid]);
   140→            }
   141→        }
   142→        
   143→        if col_idx.is_empty() {
   144→            return Array2::zeros((0, 0));
   145→        }
   146→        
   147→        if all_rows {
   148→            // Return all rows, selected columns
   149→            self.design_matrix.select(Axis(1), &col_idx)
   150→        } else {
   151→            // Get row indices for requested blocks
   152→            let mut row_idx = Vec::new();
   153→            for &bid in block_ids {
   154→                if bid < self.row_indices.len() {
   155→                    row_idx.extend(&self.row_indices[bid]);
   156→                }
   157→            }
   158→            
   159→            if row_idx.is_empty() {
   160→                return Array2::zeros((0, 0));
   161→            }
   162→            
   163→            // Return selected rows and columns
   164→            let selected_rows = self.design_matrix.select(Axis(0), &row_idx);
   165→            selected_rows.select(Axis(1), &col_idx)
   166→        }
   167→    }
   168→}
   169→
   170→/// Baseline model for fMRI time series
   171→#[derive(Debug, Clone)]
   172→pub struct BaselineModel {
   173→    /// Dictionary of baseline terms
   174→    pub terms: HashMap<String, Option<BaselineTerm>>,
   175→    /// Drift specification
   176→    pub drift_spec: BaselineSpec,
   177→    /// Sampling frame information
   178→    pub sampling_info: SamplingInfo,
   179→}
   180→
   181→impl BaselineModel {
   182→    /// Create a new baseline model
   183→    pub fn new(
   184→        terms: HashMap<String, Option<BaselineTerm>>,
   185→        drift_spec: BaselineSpec,
   186→        sampling_info: SamplingInfo,
   187→    ) -> Self {
   188→        Self {
   189→            terms,
   190→            drift_spec,
   191→            sampling_info,
   192→        }
   193→    }
   194→    
   195→    /// Get the full design matrix by combining all terms
   196→    pub fn design_matrix(&self) -> Result<Array2<f64>, ValidationError> {
   197→        let mut matrices = Vec::new();
   198→        let mut all_col_names = Vec::new();
   199→        
   200→        // Collect matrices in order: drift, block, nuisance
   201→        for term_name in &["drift", "block", "nuisance"] {
   202→            if let Some(Some(term)) = self.terms.get(*term_name) {
   203→                matrices.push(term.design_matrix.view());
   204→                all_col_names.extend(term.column_names.clone());
   205→            }
   206→        }
   207→        
   208→        if matrices.is_empty() {
   209→            // Return empty matrix with correct number of rows
   210→            let n_rows = self.sampling_info.n_scans();
   211→            return Ok(Array2::zeros((n_rows, 0)));
   212→        }
   213→        
   214→        // Concatenate along columns
   215→        let combined = concatenate(Axis(1), &matrices)
   216→            .map_err(|e| ValidationError::InvalidParameter(
   217→                format!("Failed to concatenate baseline matrices: {}", e)
   218→            ))?;
   219→        
   220→        Ok(combined)
   221→    }
   222→    
   223→    /// Get column names for the full design matrix
   224→    pub fn column_names(&self) -> Vec<String> {
   225→        let mut names = Vec::new();
   226→        
   227→        for term_name in &["drift", "block", "nuisance"] {
   228→            if let Some(Some(term)) = self.terms.get(*term_name) {
   229→                names.extend(term.column_names.clone());
   230→            }
   231→        }
   232→        
   233→        names
   234→    }
   235→}
   236→
   237→/// Construct a baseline model for fMRI time series
   238→pub fn baseline_model(
   239→    basis: BasisType,
   240→    degree: usize,
   241→    sampling_info: &SamplingInfo,
   242→    intercept: InterceptType,
   243→    nuisance_list: Option<Vec<Array2<f64>>>,
   244→) -> Result<BaselineModel, ValidationError> {
   245→    // Validate basis
   246→    if matches!(basis, BasisType::BSpline | BasisType::NaturalSpline) && degree < 3 {
   247→        return Err(ValidationError::InvalidParameter(
   248→            format!("{:?} basis must have degree >= 3", basis)
   249→        ));
   250→    }
   251→    
   252→    // Create drift specification
   253→    let drift_spec = BaselineSpec::new(degree, basis, intercept);
   254→    
   255→    // Construct terms
   256→    let mut terms = HashMap::new();
   257→    
   258→    // Always create drift term
   259→    terms.insert("drift".to_string(), Some(construct_drift_term(&drift_spec, sampling_info)?));
   260→    
   261→    // Create block term if needed
   262→    if intercept != InterceptType::None && basis != BasisType::Constant {
   263→        terms.insert("block".to_string(), Some(construct_block_term(sampling_info, intercept)?));
   264→    } else {
   265→        terms.insert("block".to_string(), None);
   266→    }
   267→    
   268→    // Create nuisance term if provided
   269→    if let Some(nuisance) = nuisance_list {
   270→        terms.insert("nuisance".to_string(), Some(make_nuisance_term(nuisance, sampling_info)?));
   271→    } else {
   272→        terms.insert("nuisance".to_string(), None);
   273→    }
   274→    
   275→    Ok(BaselineModel::new(terms, drift_spec, sampling_info.clone()))
   276→}
   277→
   278→/// Construct drift term from specification
   279→fn construct_drift_term(spec: &BaselineSpec, sinfo: &SamplingInfo) -> Result<BaselineTerm, ValidationError> {
   280→    let block_lens = sinfo.block_lengths();
   281→    
   282→    let mut matrices = Vec::new();
   283→    let mut col_indices = Vec::new();
   284→    let mut row_indices = Vec::new();
   285→    let mut column_names = Vec::new();
   286→    
   287→    let mut current_col = 0;
   288→    let mut current_row = 0;
   289→    
   290→    for (i, &block_len) in block_lens.iter().enumerate() {
   291→        // Generate time points for this block
   292→        let t: Array1<f64> = Array1::range(1.0, block_len as f64 + 1.0, 1.0);
   293→        
   294→        // Apply basis function
   295→        let block_matrix = match spec.basis {
   296→            BasisType::Constant => {
   297→                // Create constant basis (all ones)
   298→                Array2::ones((t.len(), 1))
   299→            },
   300→            BasisType::Polynomial => {
   301→                // Create polynomial basis
   302→                let basis = PolynomialBasis::new(spec.degree);
   303→                basis.evaluate(&t.view())?
   304→            },
   305→            BasisType::BSpline | BasisType::NaturalSpline => {
   306→                // Create B-spline basis  
   307→                let basis = BSplineBasis::new(spec.degree);
   308→                basis.evaluate(&t.view())?
   309→            },
   310→        };
   311→        
   312→        let n_cols = block_matrix.ncols();
   313→        matrices.push(block_matrix);
   314→        
   315→        // Track indices
   316→        col_indices.push((current_col..current_col + n_cols).collect());
   317→        row_indices.push((current_row..current_row + block_len).collect());
   318→        
   319→        // Generate column names
   320→        for j in 0..n_cols {
   321→            if spec.basis == BasisType::Constant {
   322→                column_names.push(format!("base_{}_run{}", 
   323→                    match spec.basis {
   324→                        BasisType::Constant => "constant",
   325→                        BasisType::Polynomial => "poly",
   326→                        BasisType::BSpline => "bs",
   327→                        BasisType::NaturalSpline => "ns",
   328→                    },
   329→                    i + 1
   330→                ));
   331→            } else {
   332→                column_names.push(format!("base_{}_run{}_b{}", 
   333→                    match spec.basis {
   334→                        BasisType::Constant => "constant",
   335→                        BasisType::Polynomial => "poly",
   336→                        BasisType::BSpline => "bs",
   337→                        BasisType::NaturalSpline => "ns",
   338→                    },
   339→                    i + 1,
   340→                    j + 1
   341→                ));
   342→            }
   343→        }
   344→        
   345→        current_col += n_cols;
   346→        current_row += block_len;
   347→    }
   348→    
   349→    // Handle global constant intercept
   350→    let full_matrix = if spec.basis == BasisType::Constant && spec.intercept == InterceptType::Global {
   351→        // Combine into single column
   352→        let total_rows = sinfo.n_scans();
   353→        let combined = Array2::ones((total_rows, 1));
   354→        column_names = vec!["base_constant".to_string()];
   355→        col_indices = vec![vec![0]; block_lens.len()];
   356→        combined
   357→    } else {
   358→        // Block diagonal structure
   359→        block_diagonal(&matrices)?
   360→    };
   361→    
   362→    Ok(BaselineTerm {
   363→        varname: spec.name.clone(),
   364→        design_matrix: full_matrix,
   365→        col_indices,
   366→        row_indices,
   367→        column_names,
   368→    })
   369→}
   370→
   371→/// Construct block intercept term
   372→fn construct_block_term(
   373→    sinfo: &SamplingInfo,
   374→    intercept: InterceptType,
   375→) -> Result<BaselineTerm, ValidationError> {
   376→    let block_lens = sinfo.block_lengths();
   377→    let n_blocks = block_lens.len();
   378→    let total_rows = sinfo.n_scans();
   379→    
   380→    let (matrix, column_names, col_indices) = if intercept == InterceptType::Global {
   381→        // Single intercept column
   382→        let matrix = Array2::ones((total_rows, 1));
   383→        let names = vec!["intercept".to_string()];
   384→        let indices = vec![vec![0]; n_blocks];
   385→        (matrix, names, indices)
   386→    } else {
   387→        // Runwise intercepts
   388→        let matrices: Vec<Array2<f64>> = block_lens.iter()
   389→            .map(|&len| Array2::ones((len, 1)))
   390→            .collect();
   391→        
   392→        let matrix = block_diagonal(&matrices)?;
   393→        let names: Vec<String> = (0..n_blocks)
   394→            .map(|i| format!("intercept_run{}", i + 1))
   395→            .collect();
   396→        let indices: Vec<Vec<usize>> = (0..n_blocks)
   397→            .map(|i| vec![i])
   398→            .collect();
   399→        
   400→        (matrix, names, indices)
   401→    };
   402→    
   403→    // Create row indices
   404→    let mut row_indices = Vec::new();
   405→    let mut current_row = 0;
   406→    for &block_len in block_lens {
   407→        row_indices.push((current_row..current_row + block_len).collect());
   408→        current_row += block_len;
   409→    }
   410→    
   411→    Ok(BaselineTerm {
   412→        varname: "block".to_string(),
   413→        design_matrix: matrix,
   414→        col_indices,
   415→        row_indices,
   416→        column_names,
   417→    })
   418→}
   419→
   420→/// Create nuisance term from list of matrices
   421→fn make_nuisance_term(
   422→    nuisance_list: Vec<Array2<f64>>,
   423→    sinfo: &SamplingInfo,
   424→) -> Result<BaselineTerm, ValidationError> {
   425→    let block_lens = sinfo.block_lengths();
   426→    
   427→    // Validate input
   428→    if nuisance_list.len() != block_lens.len() {
   429→        return Err(ValidationError::InvalidParameter(
   430→            format!("Length of nuisance_list ({}) must equal number of blocks ({})",
   431→                nuisance_list.len(), block_lens.len())
   432→        ));
   433→    }
   434→    
   435→    // Validate sizes and collect info
   436→    let mut matrices = Vec::new();
   437→    let mut _total_cols = 0;
   438→    
   439→    for (i, (nuisance, &block_len)) in nuisance_list.iter().zip(block_lens).enumerate() {
   440→        if nuisance.nrows() != block_len {
   441→            return Err(ValidationError::InvalidParameter(
   442→                format!("Nuisance matrix {} has {} rows but block has {} timepoints",
   443→                    i, nuisance.nrows(), block_len)
   444→            ));
   445→        }
   446→        
   447→        matrices.push(nuisance.clone());
   448→        _total_cols += nuisance.ncols();
   449→    }
   450→    
   451→    // Create block diagonal matrix
   452→    let full_matrix = block_diagonal(&matrices)?;
   453→    
   454→    // Generate column names and indices
   455→    let mut column_names = Vec::new();
   456→    let mut col_indices = Vec::new();
   457→    let mut current_col = 0;
   458→    
   459→    for (i, mat) in matrices.iter().enumerate() {
   460→        let n_cols = mat.ncols();
   461→        let mut block_cols = Vec::new();
   462→        
   463→        for j in 0..n_cols {
   464→            column_names.push(format!("nuis_run{}_c{}", i + 1, j + 1));
   465→            block_cols.push(current_col);
   466→            current_col += 1;
   467→        }
   468→        
   469→        col_indices.push(block_cols);
   470→    }
   471→    
   472→    // Generate row indices
   473→    let mut row_indices = Vec::new();
   474→    let mut current_row = 0;
   475→    
   476→    for &block_len in block_lens {
   477→        row_indices.push((current_row..current_row + block_len).collect());
   478→        current_row += block_len;
   479→    }
   480→    
   481→    Ok(BaselineTerm {
   482→        varname: "nuisance".to_string(),
   483→        design_matrix: full_matrix,
   484→        col_indices,
   485→        row_indices,
   486→        column_names,
   487→    })
   488→}
   489→
   490→/// Create block diagonal matrix from list of matrices
   491→fn block_diagonal(matrices: &[Array2<f64>]) -> Result<Array2<f64>, ValidationError> {
   492→    if matrices.is_empty() {
   493→        return Ok(Array2::zeros((0, 0)));
   494→    }
   495→    
   496→    // Get dimensions
   497→    let n_rows: usize = matrices.iter().map(|m| m.nrows()).sum();
   498→    let n_cols: usize = matrices.iter().map(|m| m.ncols()).sum();
   499→    
   500→    // Create output matrix
   501→    let mut result = Array2::zeros((n_rows, n_cols));
   502→    
   503→    // Fill blocks
   504→    let mut row_offset = 0;
   505→    let mut col_offset = 0;
   506→    
   507→    for mat in matrices {
   508→        let n_r = mat.nrows();
   509→        let n_c = mat.ncols();
   510→        
   511→        result.slice_mut(ndarray::s![row_offset..row_offset+n_r, col_offset..col_offset+n_c])
   512→            .assign(mat);
   513→        
   514→        row_offset += n_r;
   515→        col_offset += n_c;
   516→    }
   517→    
   518→    Ok(result)
   519→}

