//! Full Design Matrix Example
//! ==========================
//!
//! This example demonstrates how to create a complete design matrix
//! combining event regressors with baseline models.

use fmridesign::{DataFrame, event_model};
use fmridesign::baseline::{baseline_model, BasisType, InterceptType, SamplingInfo};
use fmridesign::sampling::uniform_sampling_frame;
use fmridesign::types::Model;
use ndarray::{Axis, concatenate};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Set up experiment parameters
    let n_scans = 300;
    let tr = 2.0;

    // Create sampling frame
    let sampling_frame = uniform_sampling_frame(n_scans, tr, Some(0.0))?;

    // Create experimental events
    let mut data = DataFrame::new();

    // Task A events (10 events, 20s apart)
    let onsets_a: Vec<f64> = (0..10).map(|i| 10.0 + i as f64 * 30.0).collect();
    let mut onsets = onsets_a.clone();
    let mut conditions = vec!["A".to_string(); 10];
    let mut durations = vec![2.0; 10];

    // Task B events (10 events, interleaved with A)
    let onsets_b: Vec<f64> = (0..10).map(|i| 25.0 + i as f64 * 30.0).collect();

    // Add parametric modulator
    let mut rt: Vec<f64> = Vec::new();
    // Slower RTs for condition A
    rt.extend(onsets_a.iter().map(|_| 1.2 + rand::random::<f64>() * 0.4));
    // Faster RTs for condition B  
    rt.extend(onsets_b.iter().map(|_| 0.8 + rand::random::<f64>() * 0.4));

    // Now extend the onsets after we've used onsets_b
    onsets.extend(onsets_b);
    conditions.extend(vec!["B".to_string(); 10]);
    durations.extend(vec![2.0; 10]);

    // Build DataFrame
    data.columns.insert("onset".to_string(), onsets);
    data.columns.insert("duration".to_string(), durations);
    data.columns.insert("rt".to_string(), rt);
    data.str_columns.insert("condition".to_string(), conditions);

    // Create event model
    println!("Creating event model...");
    let mut event_mod = event_model(
        "hrf(condition) + hrf(condition):scale(rt)",
        &data,
        tr,
        n_scans,
    )?;

    // Generate the design matrix
    let _ = event_mod.generate_design_matrix()?;

    let event_dm = event_mod.design_matrix();
    println!("Event model shape: {:?}", event_dm.shape());
    println!("Event columns: {:?}", event_mod.column_names());
    println!();

    // Create baseline model
    println!("Creating baseline model...");
    let sampling_info = SamplingInfo::from_frame(sampling_frame);

    // Use polynomial drift of degree 3 with global intercept
    let baseline_mod = baseline_model(
        BasisType::Polynomial,
        3,
        &sampling_info,
        InterceptType::Global,
        None,
    )?;

    let baseline_dm = baseline_mod.design_matrix()?;
    println!("Baseline model shape: {:?}", baseline_dm.shape());
    println!("Baseline columns: {:?}", baseline_mod.column_names());
    println!();

    // Combine event and baseline design matrices
    println!("Combining design matrices...");
    let full_dm = concatenate(
        Axis(1),
        &[event_dm.view(), baseline_dm.view()]
    )?;

    println!("Full design matrix shape: {:?}", full_dm.shape());

    // Combine column names
    let mut full_columns = event_mod.column_names().to_vec();
    full_columns.extend(baseline_mod.column_names());

